import React, { useState } from 'react';
import { textToSpeech } from '../services/geminiService';
import { playAudio } from '../utils/audio';
import SpinnerIcon from './icons/SpinnerIcon';
import PlayIcon from './icons/PlayIcon';
import DownloadIcon from './icons/DownloadIcon';

const createWavFile = (pcmData: Uint8Array, sampleRate: number, numChannels: number, bitsPerSample: number): Blob => {
    const dataSize = pcmData.length;
    const buffer = new ArrayBuffer(44 + dataSize);
    const view = new DataView(buffer);

    const writeString = (view: DataView, offset: number, string: string) => {
        for (let i = 0; i < string.length; i++) {
            view.setUint8(offset + i, string.charCodeAt(i));
        }
    }

    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + dataSize, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, numChannels, true);
    view.setUint32(24, sampleRate, true);
    const byteRate = sampleRate * numChannels * (bitsPerSample / 8);
    view.setUint32(28, byteRate, true);
    const blockAlign = numChannels * (bitsPerSample / 8);
    view.setUint16(32, blockAlign, true);
    view.setUint16(34, bitsPerSample, true);
    writeString(view, 36, 'data');
    view.setUint32(40, dataSize, true);
    new Uint8Array(buffer, 44).set(pcmData);

    return new Blob([buffer], { type: 'audio/wav' });
};

interface ReaderProps {
    onUsage: () => void;
}

const Reader: React.FC<ReaderProps> = ({ onUsage }) => {
    const [text, setText] = useState<string>('');
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [audioData, setAudioData] = useState<string | null>(null);

    const handleGenerateAudio = async () => {
        if (!text.trim()) {
            setError('Please enter some text to generate audio.');
            return;
        }
        setIsLoading(true);
        setError(null);
        setAudioData(null);

        try {
            const base64Audio = await textToSpeech(text);
            setAudioData(base64Audio);
            onUsage();
        } catch (err) {
            const errorMessage = err instanceof Error ? err.message : "An unknown error occurred during audio generation.";
            setError(errorMessage);
        } finally {
            setIsLoading(false);
        }
    };

    const decode = (base64: string): Uint8Array => {
        const binaryString = atob(base64);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);
        for (let i = 0; i < len; i++) {
            bytes[i] = binaryString.charCodeAt(i);
        }
        return bytes;
    }

    const handleDownload = () => {
        if (!audioData) return;
        try {
            const pcmData = decode(audioData);
            const wavBlob = createWavFile(pcmData, 24000, 1, 16); 
            // Cast URL.createObjectURL to string to prevent unknown to string assignment error
            const url = URL.createObjectURL(wavBlob) as string;
            const a = document.createElement('a');
            a.style.display = 'none';
            a.href = url;
            a.download = 'generated-audio.wav';
            document.body.appendChild(a);
            a.click();
            window.URL.revokeObjectURL(url);
            a.remove();
        } catch (err) {
            console.error("Download failed:", err);
            setError("Failed to create a downloadable file.");
        }
    };

    return (
        <div className="w-full flex flex-col items-center gap-6">
            <div className="w-full relative bg-surface rounded-2xl p-6 backdrop-blur-sm border border-border animate-pulse-glow">
                <textarea
                    value={text}
                    onChange={(e) => setText(e.target.value)}
                    placeholder="Type or paste your text here..."
                    className="w-full h-40 p-4 bg-black/20 text-textMain border border-border rounded-lg focus:ring-2 focus:ring-primary focus:outline-none resize-none transition-colors placeholder-textMuted"
                    disabled={isLoading}
                />
                <button
                    onClick={handleGenerateAudio}
                    disabled={isLoading || !text.trim()}
                    className="mt-4 w-full flex items-center justify-center px-6 py-3 bg-primary text-white font-semibold rounded-lg hover:bg-primary-hover transition-all transform hover:scale-105 active:scale-100 border border-border focus:outline-none focus:ring-2 focus:ring-accent disabled:opacity-50 disabled:cursor-not-allowed disabled:scale-100"
                >
                    {isLoading ? <><SpinnerIcon /> Generating...</> : 'Generate Audio'}
                </button>
            </div>

            {error && (
                <div className="w-full bg-red-900/50 border border-red-500 text-red-300 p-4 rounded-md text-center" role="alert">
                    <p>{error}</p>
                </div>
            )}

            {audioData && !isLoading && (
                <div className="w-full flex flex-col sm:flex-row items-center justify-between gap-4 bg-surface rounded-2xl p-6 backdrop-blur-sm border border-border animate-pop-in">
                    <p className="text-lg font-medium text-accent">Audio ready!</p>
                    <div className="flex items-center gap-4">
                        <button onClick={() => audioData && playAudio(audioData)} className="p-3 bg-secondary rounded-full hover:opacity-80 transition-colors focus:outline-none focus:ring-2 focus:ring-primary">
                           <PlayIcon />
                        </button>
                        <button onClick={handleDownload} className="flex items-center gap-2 px-4 py-2 bg-secondary text-white font-semibold rounded-lg hover:opacity-80 transition-colors border border-border focus:outline-none focus:ring-2 focus:ring-primary">
                           <DownloadIcon />
                           <span>Download .wav</span>
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Reader;

import React, { useState, useEffect, useRef } from 'react';
import { generateImageFrame } from '../services/geminiService';
import SpinnerIcon from './icons/SpinnerIcon';
import PlayIcon from './icons/PlayIcon';
import DownloadIcon from './icons/DownloadIcon';

interface AnimationToolProps {
  onUsage: () => void;
}

const AnimationTool: React.FC<AnimationToolProps> = ({ onUsage }) => {
  const [prompt, setPrompt] = useState('');
  const [style, setStyle] = useState('3D Render');
  const [frames, setFrames] = useState<string[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generationProgress, setGenerationProgress] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentFrameIndex, setCurrentFrameIndex] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [fps, setFps] = useState(4); 

  const styles = [
      '3D Render', 
      'Unreal Engine 5', 
      'Pixar Style', 
      'Cinematic', 
      'Cyberpunk', 
      'Realistic', 
      'Anime', 
      'Oil Painting', 
      'Claymation'
  ];

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationIntervalRef = useRef<number | null>(null);
  const TOTAL_FRAMES = 8; // Increased for smoother/longer animation

  const handleGenerate = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    setFrames([]);
    setError(null);
    setCurrentFrameIndex(0);
    setGenerationProgress(0);
    setIsPlaying(false);

    const newFrames: string[] = [];

    try {
        // Frame 1: Base Generation
        const frame1Base64 = await generateImageFrame(prompt, style);
        newFrames.push(`data:image/jpeg;base64,${frame1Base64}`);
        setFrames([...newFrames]);
        setGenerationProgress(1);

        // Subsequent Frames: Image-to-Image for consistency
        let previousFrame = frame1Base64;
        for (let i = 1; i < TOTAL_FRAMES; i++) {
            // Slight variation in prompt for movement
            const movementPrompt = `Continue the action: ${prompt}. Frame ${i + 1} of ${TOTAL_FRAMES}. Slight movement.`;

            const nextFrameBase64 = await generateImageFrame(movementPrompt, style, previousFrame);
            newFrames.push(`data:image/jpeg;base64,${nextFrameBase64}`);
            setFrames([...newFrames]);
            setGenerationProgress(i + 1);
            previousFrame = nextFrameBase64;
        }

        onUsage();
        setIsPlaying(true); // Auto-play on finish
    } catch (err: any) {
        setError("Failed to generate frames. Please try again.");
        console.error(err);
    } finally {
        setIsGenerating(false);
    }
  };

  // Animation Loop
  useEffect(() => {
    if (isPlaying && frames.length > 0) {
       animationIntervalRef.current = window.setInterval(() => {
           setCurrentFrameIndex(prev => (prev + 1) % frames.length);
       }, 1000 / fps);
    } else {
        if (animationIntervalRef.current) {
            clearInterval(animationIntervalRef.current);
        }
    }
    return () => {
        if (animationIntervalRef.current) clearInterval(animationIntervalRef.current);
    };
  }, [isPlaying, frames, fps]);

  // Draw to Canvas
  useEffect(() => {
      const canvas = canvasRef.current;
      if (canvas && frames.length > 0 && frames[currentFrameIndex]) {
          const ctx = canvas.getContext('2d');
          const img = new Image();
          img.onload = () => {
              // Maintain aspect ratio
              const aspectRatio = img.width / img.height;
              canvas.height = canvas.width / aspectRatio;

              // Clear and Draw
              ctx?.clearRect(0, 0, canvas.width, canvas.height);
              ctx?.drawImage(img, 0, 0, canvas.width, canvas.height);
          };
          img.src = frames[currentFrameIndex];
      }
  }, [currentFrameIndex, frames]);

  const handleDownloadVideo = () => {
      const canvas = canvasRef.current;
      if (!canvas) return;

      const stream = (canvas as any).captureStream(30); // Capture at 30 FPS for smoothness

      // Prefer better codecs if available
      let mimeType = 'video/webm';
      if (MediaRecorder.isTypeSupported('video/webm;codecs=vp9')) {
          mimeType = 'video/webm;codecs=vp9';
      } else if (MediaRecorder.isTypeSupported('video/mp4')) {
          mimeType = 'video/mp4';
      }

      const mediaRecorder = new MediaRecorder(stream, { 
          mimeType,
          videoBitsPerSecond: 5000000 // 5 Mbps for high quality
      });

      const chunks: Blob[] = [];

      mediaRecorder.ondataavailable = (e) => {
          if (e.data.size > 0) chunks.push(e.data);
      };

      mediaRecorder.onstop = () => {
          const blob = new Blob(chunks, { type: mimeType });
          // Cast URL.createObjectURL result to string to prevent unknown to string assignment error
          const url = URL.createObjectURL(blob) as string;
          const a = document.createElement('a');
          a.href = url;
          const ext = mimeType.includes('mp4') ? 'mp4' : 'webm';
          a.download = `ai-animation-hq.${ext}`;
          document.body.appendChild(a);
          a.click();
          window.URL.revokeObjectURL(url);
          a.remove();
      };

      mediaRecorder.start();

      // Force play through all frames once to record
      setIsPlaying(false); // Stop UI loop
      let frame = 0;
      const recInterval = setInterval(() => {
          if (frame >= frames.length) {
              clearInterval(recInterval);
              mediaRecorder.stop();
              setIsPlaying(true); // Resume UI loop
          } else {
             setCurrentFrameIndex(frame);
             frame++;
          }
      }, 1000 / fps);
  };

  return (
    <div className="w-full max-w-4xl mx-auto space-y-6">
        {/* Controls Section */}
        <div className="bg-surface p-6 rounded-2xl backdrop-blur-sm border border-border animate-pop-in shadow-xl">
            <div className="flex justify-between items-start mb-6">
                <div>
                    <h2 className="text-2xl font-bold text-textMain mb-1 flex items-center gap-2">
                        <span className="text-secondary">AI</span> Animation Studio
                    </h2>
                    <p className="text-textSub text-sm">Create high-fidelity sequential animations.</p>
                </div>
                <span className="px-2 py-1 bg-accent/20 border border-accent/50 rounded text-[10px] font-bold text-accent tracking-wide uppercase">
                    High Quality
                </span>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
                <div className="md:col-span-2">
                    <label className="text-xs text-textSub font-bold mb-2 block uppercase tracking-wider">Animation Prompt</label>
                    <div className="relative">
                        <input 
                            type="text"
                            value={prompt}
                            onChange={e => setPrompt(e.target.value)}
                            placeholder="e.g. A futuristic city with flying cars..."
                            className="w-full pl-4 pr-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-2 focus:ring-secondary outline-none transition-all"
                            disabled={isGenerating}
                        />
                    </div>
                </div>
                <div>
                    <label className="text-xs text-textSub font-bold mb-2 block uppercase tracking-wider">Art Style</label>
                    <select 
                        value={style}
                        onChange={e => setStyle(e.target.value)}
                        className="w-full px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-2 focus:ring-secondary outline-none cursor-pointer transition-all"
                        disabled={isGenerating}
                    >
                        {styles.map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                </div>
            </div>

            <button 
                onClick={handleGenerate}
