import { GoogleGenAI, Type, Modality } from "@google/genai";
import { QuestionData } from "../types";

// Simple in-memory cache for TTS to avoid redundant API calls
const ttsCache = new Map<string, string>();

export async function processQuestionImage(imageBase64: string): Promise<QuestionData> {
  // Create a new instance right before the call to ensure fresh API key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imagePart = {
    inlineData: {
      mimeType: 'image/jpeg',
      data: imageBase64,
    },
  };

  // Optimized prompt to be concise and token-efficient
  const textPart = {
    text: `Analyze this image of a multiple-choice question. Return a JSON object with:
      1. "question": The question text (remove leading numbers like "1.").
      2. "options": Array of objects with "letter" (e.g., "A") and "text".
      3. "correctOption": The letter of the correct answer (indicated by bold text, checkmarks, or visual cues). If uncertain, default to the first option.`,
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [textPart, imagePart] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          options: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                letter: { type: Type.STRING },
                text: { type: Type.STRING },
              },
              required: ['letter', 'text'],
            },
          },
          correctOption: { type: Type.STRING },
        },
        required: ['question', 'options', 'correctOption'],
      },
    },
  });

  const jsonString = (response.text || "").trim();
  try {
    return JSON.parse(jsonString) as QuestionData;
  } catch (e) {
    console.error("Failed to parse JSON from Gemini:", jsonString);
    throw new Error("The AI response was not in the expected format.");
  }
}

async function attemptTextToSpeech(text: string): Promise<string> {
    // Check cache first
    if (ttsCache.has(text)) {
        return ttsCache.get(text)!;
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: {
                    prebuiltVoiceConfig: { voiceName: 'Charon' },
                },
            },
        },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

    if (!base64Audio) {
        throw new Error("API returned no audio data.");
    }

    // Store in cache
    ttsCache.set(text, base64Audio);

    return base64Audio;
}

export async function textToSpeech(text: string, retries = 3, delay = 500): Promise<string> {
    try {
        return await attemptTextToSpeech(text);
    } catch (error) {
        if (retries > 0) {
            console.warn(`TTS request failed, retrying... (${retries} left)`);
            await new Promise(resolve => setTimeout(resolve, delay));
            return textToSpeech(text, retries - 1, delay * 2);
        } else {
            console.error(`TTS request failed for "${text}" after all retries.`, error);
            throw new Error("Failed to generate audio.");
        }
    }
}

export async function generateImageFrame(prompt: string, style: string, previousFrameBase64?: string): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    let refinedPrompt = "";
    const parts: any[] = [];

    // High quality modifiers to boost visual fidelity
    const qualityBoosters = "8k resolution, highly detailed, cinematic lighting, masterpiece, professional render, sharp focus, high fidelity";

    if (previousFrameBase64) {
        refinedPrompt = `This is the PREVIOUS frame of an animation. Generate the NEXT frame. 
        ACTION: ${prompt}.
        CONSTRAINT: You MUST keep the exact same character, setting, lighting, and style as the previous frame. Only move the subject slightly to create smooth motion. Do not change colors or background.
        STYLE: ${style}.
