        parts.push({ text: refinedPrompt });
        parts.push({
            inlineData: {
                mimeType: 'image/jpeg',
                data: previousFrameBase64
            }
        });
    } else {
        refinedPrompt = `Create a cinematic keyframe for an animation. 
        SCENE: ${prompt}.
        STYLE: ${style}.
        QUALITY: ${qualityBoosters}.
        Ensure clear composition and distinct features so it can be animated later.`;

        parts.push({ text: refinedPrompt });
    }

    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
