import SpinnerIcon from './icons/SpinnerIcon';
import PlayIcon from './icons/PlayIcon';
import DownloadIcon from './icons/DownloadIcon';

const createWavFile = (pcmData: Uint8Array, sampleRate: number, numChannels: number, bitsPerSample: number): Blob => {
    const dataSize = pcmData.length;
    const buffer = new ArrayBuffer(44 + dataSize);
    const view = new DataView(buffer);

    const writeString = (view: DataView, offset: number, string: string) => {
        for (let i = 0; i < string.length; i++) {
            view.setUint8(offset + i, string.charCodeAt(i));
        }
    }

    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + dataSize, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, numChannels, true);
    view.setUint32(24, sampleRate, true);
    const byteRate = sampleRate * numChannels * (bitsPerSample / 8);
    view.setUint32(28, byteRate, true);
    const blockAlign = numChannels * (bitsPerSample / 8);
    view.setUint16(32, blockAlign, true);
    view.setUint16(34, bitsPerSample, true);
    writeString(view, 36, 'data');
    view.setUint32(40, dataSize, true);
    new Uint8Array(buffer, 44).set(pcmData);

    return new Blob([buffer], { type: 'audio/wav' });
};

interface ReaderProps {
    onUsage: () => void;
}

const Reader: React.FC<ReaderProps> = ({ onUsage }) => {
    const [text, setText] = useState<string>('');
    const [language, setLanguage] = useState<string>('English');
    const [tone, setTone] = useState<string>('Professional');
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [audioData, setAudioData] = useState<string | null>(null);

    const languages = ['English', 'Marathi', 'Hindi'];
    const tones = ['Professional', 'Friendly', 'Excited', 'Calm'];

    const handleGenerateAudio = async () => {
        if (!text.trim()) {
            setError('Please enter some text to generate audio.');
            return;
        }
        setIsLoading(true);
        setError(null);
        setAudioData(null);

        try {
            const base64Audio = await textToSpeech(text, language, tone);
            setAudioData(base64Audio);
            onUsage();
        } catch (err) {
            const errorMessage = err instanceof Error ? err.message : "An unknown error occurred during audio generation.";
            setError(errorMessage);
        } finally {
            setIsLoading(false);
        }
    };

    const decode = (base64: string): Uint8Array => {
        const binaryString = atob(base64);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);
        for (let i = 0; i < len; i++) {
            bytes[i] = binaryString.charCodeAt(i);
        }
        return bytes;
    }

    const handleDownload = () => {
        if (!audioData) return;
        try {
            const pcmData = decode(audioData);
            const wavBlob = createWavFile(pcmData, 24000, 1, 16); 
            const url = (URL.createObjectURL(wavBlob) as any) as string;
            const a = document.createElement('a');
            a.style.display = 'none';
            a.href = url;
            a.download = `speech-${language.toLowerCase()}.wav`;
            document.body.appendChild(a);
            a.click();
            window.URL.revokeObjectURL(url);
            a.remove();
        } catch (err) {
            console.error("Download failed:", err);
            setError("Failed to create a downloadable file.");
        }
    };

    return (
        <div className="w-full flex flex-col items-center gap-6">
            <div className="w-full relative bg-surface rounded-2xl p-6 backdrop-blur-sm border border-border animate-pulse-glow">

                {/* Controls Bar */}
                <div className="flex flex-wrap gap-4 mb-4 items-end">
                    <div className="flex-1 min-w-[140px]">
                        <label className="text-[10px] uppercase font-black text-textSub mb-1 block">Language Context</label>
                        <div className="flex bg-black/30 rounded-lg p-1 border border-border">
                            {languages.map(lang => (
                                <button
                                    key={lang}
                                    onClick={() => setLanguage(lang)}
                                    className={`flex-1 py-1.5 px-3 text-xs font-bold rounded-md transition-all ${language === lang ? 'bg-primary text-white shadow-lg' : 'text-textMuted hover:text-textMain'}`}
                                >
                                    {lang}
                                </button>
                            ))}
                        </div>
                    </div>
                    <div className="flex-1 min-w-[140px]">
                        <label className="text-[10px] uppercase font-black text-textSub mb-1 block">Voice Tone</label>
                        <select 
                            value={tone}
                            onChange={(e) => setTone(e.target.value)}
                            className="w-full bg-black/30 border border-border rounded-lg px-3 py-2 text-xs text-textMain outline-none focus:ring-1 focus:ring-primary"
                        >
                            {tones.map(t => <option key={t} value={t}>{t}</option>)}
                        </select>
                    </div>
                </div>

                <textarea
                    value={text}
                    onChange={(e) => setText(e.target.value)}
                    placeholder={language === 'English' ? "Type text here..." : `Type in ${language} (Devanagari script recommended for best results)...`}
                    className="w-full h-40 p-4 bg-black/20 text-textMain border border-border rounded-lg focus:ring-2 focus:ring-primary focus:outline-none resize-none transition-colors placeholder-textMuted"
                    disabled={isLoading}
                />

                <button
                    onClick={handleGenerateAudio}
                    disabled={isLoading || !text.trim()}
                    className="mt-4 w-full flex items-center justify-center px-6 py-4 bg-primary text-white font-bold rounded-xl hover:bg-primary-hover transition-all transform hover:scale-[1.01] active:scale-100 border border-border focus:outline-none focus:ring-2 focus:ring-accent disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    {isLoading ? (
                        <div className="flex items-center gap-3">
                            <SpinnerIcon /> 
                            <span>Applying {language} phonetics...</span>
                        </div>
                    ) : `Speak in ${language}`}
                </button>

                <p className="mt-3 text-[10px] text-textMuted text-center">
                    Pro tip: For Marathi/Hindi, use Devanagari script (e.g. नमस्ते) for 40% better naturalness.
                </p>
            </div>

            {error && (
                <div className="w-full bg-red-900/50 border border-red-500 text-red-300 p-4 rounded-md text-center" role="alert">
                    <p>{error}</p>
                </div>
            )}

            {audioData && !isLoading && (
                <div className="w-full flex flex-col sm:flex-row items-center justify-between gap-4 bg-surface rounded-2xl p-6 backdrop-blur-sm border border-border animate-pop-in">
                    <div>
                        <p className="text-lg font-bold text-accent">Speech Synthesized</p>
                        <p className="text-xs text-textSub">{language} • {tone} Tone</p>
                    </div>
                    <div className="flex items-center gap-4">
                        <button onClick={() => audioData && playAudio(audioData)} className="p-4 bg-primary rounded-full hover:scale-110 shadow-lg shadow-primary/20 transition-all focus:outline-none">
                           <PlayIcon />
                        </button>
                        <button onClick={handleDownload} className="flex items-center gap-2 px-6 py-3 bg-secondary text-white font-bold rounded-xl hover:opacity-90 transition-all border border-border focus:outline-none">
                           <DownloadIcon />
                           <span>Download</span>
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

