import SpinnerIcon from './icons/SpinnerIcon';
import PlayIcon from './icons/PlayIcon';
import DownloadIcon from './icons/DownloadIcon';
import SettingsIcon from './icons/SettingsIcon';

const createWavFile = (pcmData: Uint8Array, sampleRate: number, numChannels: number, bitsPerSample: number): Blob => {
    const dataSize = pcmData.length;
    const buffer = new ArrayBuffer(44 + dataSize);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => {
        for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + dataSize, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, numChannels, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * numChannels * (bitsPerSample / 8), true);
    view.setUint16(32, numChannels * (bitsPerSample / 8), true);
    view.setUint16(34, bitsPerSample, true);
    writeString(view, 36, 'data');
    view.setUint32(40, dataSize, true);
    new Uint8Array(buffer, 44).set(pcmData);
    return new Blob([buffer], { type: 'audio/wav' });
};

interface ReaderProps {
    onUsage: () => void;
}

const Reader: React.FC<ReaderProps> = ({ onUsage }) => {
    const [text, setText] = useState<string>('');
    const [language, setLanguage] = useState<string>('English');
    const [tone, setTone] = useState<string>('Professional');
    const [style, setStyle] = useState<string>('Instructional');
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [isPreviewing, setIsPreviewing] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);
    const [audioData, setAudioData] = useState<string | null>(null);
    const [isEditing, setIsEditing] = useState<boolean>(true);

    const languages = ['English', 'Marathi', 'Hindi'];
    const styles = ['Narrative', 'Conversational', 'Instructional'];
    const tones = [
        { id: 'Friendly', desc: 'Warm and approachable' },
        { id: 'Professional', desc: 'Clear and formal' },
        { id: 'Excited', desc: 'Energetic and bright' },
        { id: 'Calm', desc: 'Peaceful and steady' }
    ];

    // Persistence Logic
    useEffect(() => {
        const savedUser = localStorage.getItem('active_user');
        if (savedUser) {
            const { email } = JSON.parse(savedUser);
            const savedSettings = localStorage.getItem(`tts_prefs_${email}`);
            if (savedSettings) {
                const prefs = JSON.parse(savedSettings);
                setLanguage(prefs.language || 'English');
                setTone(prefs.tone || 'Professional');
                setStyle(prefs.style || 'Instructional');
            }
        }
    }, []);

    const savePreferences = () => {
        const savedUser = localStorage.getItem('active_user');
        if (savedUser) {
            const { email } = JSON.parse(savedUser);
            localStorage.setItem(`tts_prefs_${email}`, JSON.stringify({ language, tone, style }));
        }
    };

    const handleAudition = async (targetTone: string) => {
        setIsPreviewing(targetTone);
        setError(null);
        try {
            const sampleText = language === 'English' 
                ? `Hello! This is a sample of my ${targetTone} voice.`
                : language === 'Marathi' 
                    ? `नमस्कार! हा माझ्या ${targetTone} आवाजाचा नमुना आहे.`
                    : `नमस्ते! यह मेरी ${targetTone} आवाज़ का एक नमूना है।`;

            const base64Audio = await textToSpeech(sampleText, language, targetTone);
            await playAudio(base64Audio);
        } catch (err) {
            setError("Audition failed. Try again.");
        } finally {
            setIsPreviewing(null);
        }
    };

    const handleGenerateAudio = async () => {
        if (!text.trim()) {
            setError('Please enter some text to generate audio.');
            return;
        }
        setIsLoading(true);
        setError(null);
        setAudioData(null);

        try {
            const contextText = `Style: ${style}. Text: ${text}`;
            const base64Audio = await textToSpeech(contextText, language, tone);
            setAudioData(base64Audio);
            savePreferences();
            setIsEditing(false);
            onUsage();
        } catch (err) {
            setError(err instanceof Error ? err.message : "Generation failed.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleDownload = () => {
        if (!audioData) return;
        try {
            const binary = atob(audioData);
            const bytes = new Uint8Array(binary.length);
            for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
            const wavBlob = createWavFile(bytes, 24000, 1, 16); 
            const url = URL.createObjectURL(wavBlob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `tts-${language.toLowerCase()}-${tone.toLowerCase()}.wav`;
            a.click();
            URL.revokeObjectURL(url);
        } catch (err) {
            setError("Download failed.");
        }
    };

    return (
        <div className="w-full flex flex-col gap-6 animate-pop-in">
            {/* Header / Stats */}
            <div className="flex items-center justify-between px-2">
                <h2 className="text-xl font-black text-textMain tracking-tight">Voice Laboratory</h2>
                <div className="flex gap-2">
                    {audioData && (
                        <button 
                            onClick={() => setIsEditing(!isEditing)} 
                            className={`px-3 py-1.5 rounded-lg text-xs font-bold border transition-all ${isEditing ? 'bg-accent text-white border-accent' : 'bg-surface text-textSub border-border'}`}
                        >
                            {isEditing ? 'Viewing Settings' : 'Edit Settings'}
                        </button>
                    )}
                </div>
            </div>

            <div className={`grid grid-cols-1 lg:grid-cols-12 gap-6 transition-all duration-500`}>
                {/* Left Column: Controls */}
                <div className={`${audioData && !isEditing ? 'lg:col-span-4' : 'lg:col-span-5'} flex flex-col gap-4`}>

                    {/* Language Selector */}
                    <div className="bg-surface p-4 rounded-2xl border border-border">
                        <label className="text-[10px] uppercase font-black text-textMuted mb-3 block tracking-widest">Target Language</label>
                        <div className="flex flex-col gap-2">
                            {languages.map(lang => (
                                <button
                                    key={lang}
                                    onClick={() => setLanguage(lang)}
                                    className={`flex items-center justify-between px-4 py-3 rounded-xl border transition-all ${language === lang ? 'bg-primary/20 border-primary text-primary' : 'bg-black/20 border-transparent text-textSub hover:bg-black/30'}`}
                                >
                                    <span className="font-bold">{lang}</span>
                                    {language === lang && <div className="w-2 h-2 bg-primary rounded-full animate-pulse"></div>}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Style Selector */}
                    <div className="bg-surface p-4 rounded-2xl border border-border">
                        <label className="text-[10px] uppercase font-black text-textMuted mb-3 block tracking-widest">Content Style</label>
                        <div className="grid grid-cols-1 gap-2">
                            {styles.map(s => (
                                <button
                                    key={s}
                                    onClick={() => setStyle(s)}
                                    className={`px-4 py-2 rounded-xl text-sm font-bold border transition-all ${style === s ? 'bg-secondary/20 border-secondary text-secondary' : 'bg-black/20 border-transparent text-textSub hover:bg-black/30'}`}
                                >
                                    {s}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Center Column: Text & Tone */}
                <div className={`${audioData && !isEditing ? 'lg:col-span-8' : 'lg:col-span-7'} flex flex-col gap-6`}>

                    {/* Input Area */}
                    <div className="bg-surface p-1 rounded-3xl border border-border shadow-2xl relative overflow-hidden">
                        <textarea
                            value={text}
                            onChange={(e) => setText(e.target.value)}
                            placeholder={`Type text in ${language}...`}
                            className="w-full h-48 p-6 bg-transparent text-textMain text-lg border-none focus:ring-0 resize-none placeholder-textMuted transition-all"
                            disabled={isLoading}
                        />
                        <div className="absolute bottom-4 right-4 text-[10px] font-mono text-textMuted">
                            {text.length} characters
                        </div>
                    </div>

                    {/* Tone Personality Grid */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {tones.map(t => (
                            <div 
                                key={t.id}
                                onClick={() => setTone(t.id)}
                                className={`group p-4 rounded-2xl border-2 cursor-pointer transition-all ${tone === t.id ? 'bg-accent/10 border-accent shadow-lg shadow-accent/10' : 'bg-surface border-border hover:border-textSub'}`}
                            >
                                <div className="flex items-center justify-between mb-1">
                                    <span className={`font-bold ${tone === t.id ? 'text-accent' : 'text-textMain'}`}>{t.id}</span>
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); handleAudition(t.id); }}
                                        disabled={isPreviewing !== null}
                                        className={`p-2 rounded-full transition-all ${isPreviewing === t.id ? 'bg-accent text-white' : 'bg-black/20 text-textSub hover:bg-accent hover:text-white'}`}
                                        title="Audition this voice"
                                    >
                                        {isPreviewing === t.id ? <SpinnerIcon /> : <PlayIcon />}
                                    </button>
                                </div>
                                <p className="text-[10px] text-textMuted leading-tight">{t.desc}</p>
                            </div>
                        ))}
                    </div>

                    {/* Main Action */}
                    <button
                        onClick={handleGenerateAudio}
                        disabled={isLoading || !text.trim()}
                        className={`w-full py-5 px-6 rounded-2xl font-black text-xl transition-all transform flex items-center justify-center gap-4 shadow-xl border border-white/10 ${isLoading ? 'bg-surface text-textSub' : 'bg-gradient-to-r from-primary to-accent text-white hover:scale-[1.01] active:scale-95'}`}
                    >
                        {isLoading ? (
                            <>
                                <SpinnerIcon /> 
                                <span className="animate-pulse">Synthesizing {language}...</span>
                            </>
                        ) : audioData ? 'Recreate Speech' : 'Generate Speech'}
                    </button>
                </div>
            </div>

            {/* Error Feedback */}
            {error && (
                <div className="w-full bg-red-900/40 border border-red-500 text-red-300 p-4 rounded-2xl text-center text-sm">
                    {error}
                </div>
            )}

            {/* Result Stage */}
            {audioData && !isLoading && !isEditing && (
                <div className="w-full bg-surface rounded-3xl p-8 border border-accent/30 shadow-2xl animate-slide-fade-in flex flex-col sm:flex-row items-center justify-between gap-6 relative overflow-hidden group">
                    <div className="absolute top-0 left-0 w-1 h-full bg-accent"></div>
                    <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-2">
                             <div className="w-2 h-2 bg-accent rounded-full animate-ping"></div>
                             <span className="text-xs font-black uppercase tracking-widest text-accent">Production Ready</span>
                        </div>
                        <h3 className="text-2xl font-bold text-textMain">{language} {tone} Voice</h3>
                        <p className="text-sm text-textSub max-w-sm line-clamp-1 italic">"{text}"</p>
                    </div>
                    <div className="flex items-center gap-4">
                        <button 
                            onClick={() => playAudio(audioData)} 
                            className="w-16 h-16 bg-accent text-white rounded-full flex items-center justify-center hover:scale-110 shadow-xl shadow-accent/20 transition-all focus:outline-none"
                        >
                            <PlayIcon />
                        </button>
                        <button 
                            onClick={handleDownload} 
                            className="flex items-center gap-2 px-8 py-4 bg-secondary text-white font-black rounded-2xl hover:opacity-90 transition-all border border-white/10 shadow-lg"
                        >
                            <DownloadIcon />
                            <span>Download WAV</span>
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

