import { GoogleGenAI, Type, Modality } from "@google/genai";
import { QuestionData } from "../types";

// Simple in-memory cache for TTS to avoid redundant API calls
const ttsCache = new Map<string, string>();

export async function processQuestionImage(imageBase64: string): Promise<QuestionData> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imagePart = {
    inlineData: {
      mimeType: 'image/jpeg',
      data: imageBase64,
    },
  };

  const textPart = {
    text: `Analyze this image of a multiple-choice question. Return a JSON object with:
      1. "question": The question text (remove leading numbers like "1.").
      2. "options": Array of objects with "letter" (e.g., "A") and "text".
      3. "correctOption": The letter of the correct answer (indicated by bold text, checkmarks, or visual cues). If uncertain, default to the first option.`,
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [textPart, imagePart] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          options: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                letter: { type: Type.STRING },
                text: { type: Type.STRING },
              },
              required: ['letter', 'text'],
            },
          },
          correctOption: { type: Type.STRING },
        },
        required: ['question', 'options', 'correctOption'],
      },
    },
  });

  const jsonString = (response.text || "").trim();
  try {
    return JSON.parse(jsonString) as QuestionData;
  } catch (e) {
    console.error("Failed to parse JSON from Gemini:", jsonString);
    throw new Error("The AI response was not in the expected format.");
  }
}

async function attemptTextToSpeech(text: string, language?: string, tone?: string, style?: string): Promise<string> {
    const cacheKey = `${language || 'auto'}-${tone || 'neutral'}-${style || 'general'}-${text}`;
    if (ttsCache.has(cacheKey)) {
        return ttsCache.get(cacheKey)!;
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Detailed prompt for naturalness and prosody
    let speechInstruction = "Speak this text naturally and clearly";

    if (language === 'Marathi') {
        speechInstruction = "Speak this text in natural Marathi with authentic Maharashtrian intonation and precise pronunciation";
    } else if (language === 'Hindi') {
        speechInstruction = "Speak this text in standard Hindi with natural cadence and clear diction";
    }

    if (tone) {
        speechInstruction += `, using a ${tone.toLowerCase()} and expressive tone`;
    }

    if (style) {
        speechInstruction += `. The context of this speech is ${style.toLowerCase()}`;
    }

    const fullPrompt = `${speechInstruction}:\n\n${text}`;

    const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: fullPrompt }] }],
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: {
                    // Optimized for high quality across Hindi, Marathi, and English scripts
                    prebuiltVoiceConfig: { voiceName: 'Zephyr' },
                },
            },
        },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

    if (!base64Audio) {
        throw new Error("API returned no audio data.");
    }

    ttsCache.set(cacheKey, base64Audio);
    return base64Audio;
}

export async function textToSpeech(text: string, language?: string, tone?: string, style?: string, retries = 3, delay = 500): Promise<string> {
    try {
        return await attemptTextToSpeech(text, language, tone, style);
    } catch (error) {
        if (retries > 0) {
            console.warn(`TTS request failed, retrying... (${retries} left)`);
            await new Promise(resolve => setTimeout(resolve, delay));
            return textToSpeech(text, language, tone, style, retries - 1, delay * 2);
        } else {
            console.error(`TTS request failed for "${text}" after all retries.`, error);
            throw new Error("Failed to generate audio.");
        }
    }
}

export async function generateImageFrame(prompt: string, style: string, previousFrameBase64?: string): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    let refinedPrompt = "";
    const parts: any[] = [];

    const qualityBoosters = "8k resolution, highly detailed, cinematic lighting, masterpiece, professional render, sharp focus, high fidelity";

    if (previousFrameBase64) {
        refinedPrompt = `This is the PREVIOUS frame of an animation. Generate the NEXT frame. 
        ACTION: ${prompt}.
        CONSTRAINT: You MUST keep the exact same character, setting, lighting, and style as the previous frame. Only move the subject slightly to create smooth motion. Do not change colors or background.
        STYLE: ${style}.
        QUALITY: ${qualityBoosters}.`;

        parts.push({ text: refinedPrompt });
        parts.push({
            inlineData: {
                mimeType: 'image/jpeg',
                data: previousFrameBase64
            }
        });
    } else {
        refinedPrompt = `Create a cinematic keyframe for an animation. 
        SCENE: ${prompt}.
        STYLE: ${style}.
        QUALITY: ${qualityBoosters}.
        Ensure clear composition and distinct features so it can be animated later.`;

        parts.push({ text: refinedPrompt });
    }

    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts },
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData && part.inlineData.data) {
            return part.inlineData.data;
        }
    }

    throw new Error("No image data returned from Gemini.");
}

