                        >
                            <PlayIcon className="w-10 h-10" />
                        </button>
                        <button 
                            onClick={handleDownload} 
                            className="flex items-center gap-3 px-10 py-5 bg-black/40 text-white font-black rounded-2xl hover:bg-black/60 transition-all border border-white/5 shadow-lg"
                        >
                            <DownloadIcon />
                            <span>Export WAV</span>
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

