            {currentView === 'MCQ_READER' && (
            <>
              {displayError && (
                <div className="bg-red-900/50 border border-red-500 text-red-300 p-4 mb-6 rounded-md text-center" role="alert">
                  <p className="font-bold">Error</p>
                  <p>{displayError}</p>
                </div>
              )}

              <div className="h-8 mb-4 text-center text-textSub flex items-center justify-center space-x-2">
                {(getStatusMessage()) && <SpinnerIcon />}
                <span>{getStatusMessage()}</span>
                {questionQueue.length > 0 && ![AppState.PROCESSING_IMAGE, AppState.PREPARING_AUDIO].includes(appState) && !showTryAgain &&
                  <span className="font-semibold">({currentQuestionIndex + 1}/{questionQueue.length})</span>
                }
              </div>

              {!currentQuestion && !showTryAgain ? (
                <>
                  <div className="flex items-center justify-center mb-4 space-x-2 p-2 rounded-md bg-surface">
                      <input
                          type="checkbox"
                          id="record-session"
                          checked={isRecordingEnabled}
                          onChange={(e) => setIsRecordingEnabled(e.target.checked)}
                          className="w-4 h-4 text-primary bg-gray-700 border-border rounded focus:ring-primary focus:ring-offset-gray-800"
                      />
                      <label htmlFor="record-session" className="text-sm font-medium text-textSub cursor-pointer">
                          Record Session (Screen + Audio)
                      </label>
                  </div>
                  <FileUpload onFileSelect={handleFileSelect} disabled={appState === AppState.PROCESSING_IMAGE || AppState.PREPARING_AUDIO} />
                </>
              ) : (currentQuestion && 
                <div className="relative bg-surface rounded-2xl p-6 sm:p-8 backdrop-blur-sm border border-border animate-pulse-glow">
                  <QuestionDisplay 
                    questionData={currentQuestion} 
                    highlightedOption={highlightedOption}
                  />
                  {appState === AppState.COUNTDOWN && countdown !== null && (
                    <div className="absolute inset-0 bg-black/40 flex items-center justify-center rounded-lg z-10">
                        <span key={countdown} className="text-9xl font-bold text-white animate-pop-in select-none">{countdown}</span>
                    </div>
                  )}
                </div>
              )}

               {showTryAgain && (
                 <div className="mt-8 text-center flex flex-col sm:flex-row gap-4 justify-center">
                    <button 
                      onClick={resetToHome}
                      disabled={isFinalizingRecording}
                      className="px-8 py-3 bg-secondary text-white font-semibold rounded-lg hover:opacity-90 transition-all transform hover:scale-105 border border-border disabled:opacity-50 disabled:cursor-not-allowed">
                      Back to Home
                    </button>
                    {finalRecording && (
                      <button 
                        onClick={handleDownloadRecording}
                        className="px-8 py-3 bg-primary text-white font-semibold rounded-lg hover:bg-primary-hover transition-all transform hover:scale-105 border border-border">
                        Download Recording
                      </button>
                    )}
                 </div>
              )}
            </>
            )}
            {currentView === 'READER' && (
                <Suspense fallback={<div className="flex justify-center p-10 text-primary"><SpinnerIcon /></div>}>
                    <Reader onUsage={() => trackUsage('TTS')} />
                </Suspense>
            )}
            {currentView === 'VIDEO_MAKER' && (
                <Suspense fallback={<div className="flex justify-center p-10 text-primary"><SpinnerIcon /></div>}>
                    <AnimationTool onUsage={() => trackUsage('VIDEO')} />
                </Suspense>
            )}
        </main>
        <footer className="text-center mt-8 text-sm text-textSub">
            <p>Powered by Google Gemini</p>
            <button onClick={() => setUser(null)} className="text-xs mt-2 text-primary hover:text-textMain underline">Logout ({user.name})</button>
        </footer>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { textToSpeech, restructureText } from '../services/geminiService';
import { playAudio } from '../utils/audio';
import SpinnerIcon from './icons/SpinnerIcon';
import PlayIcon from './icons/PlayIcon';
import DownloadIcon from './icons/DownloadIcon';
import SparklesIcon from './icons/SparklesIcon';

const createWavFile = (pcmData: Uint8Array, sampleRate: number, numChannels: number, bitsPerSample: number): Blob => {
    const dataSize = pcmData.length;
    const buffer = new ArrayBuffer(44 + dataSize);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => {
        for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + dataSize, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, numChannels, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * numChannels * (bitsPerSample / 8), true);
    view.setUint16(32, numChannels * (bitsPerSample / 8), true);
    view.setUint16(34, bitsPerSample, true);
    writeString(view, 36, 'data');
    view.setUint32(40, dataSize, true);
    new Uint8Array(buffer, 44).set(pcmData);
    return new Blob([buffer], { type: 'audio/wav' });
};

interface VoiceOption {
    id: string;
    name: string;
    description: string;
    tones: string[];
}

const MALE_VOICES: VoiceOption[] = [
    { id: 'Puck', name: 'Alpha', description: 'Bright, youthful, and vibrant.', tones: ['Energetic', 'Casual', 'Friendly'] },
    { id: 'Charon', name: 'Bravo', description: 'Deep, steady, and professional.', tones: ['Authoritative', 'Formal', 'Calm'] },
    { id: 'Fenrir', name: 'Delta', description: 'Mature, gritty, and wise.', tones: ['Narrative', 'Intense', 'Soft'] }
];

const AI_PRESETS = [
    { label: 'Fix Grammar', instruction: 'Correct all grammar and punctuation errors while keeping the meaning identical.' },
    { label: 'More Professional', instruction: 'Rewrite this to sound more formal, professional, and authoritative.' },
    { label: 'Summarize', instruction: 'Keep the core meaning but make the text significantly more concise.' },
    { label: 'Add Excitement', instruction: 'Make the tone more enthusiastic and energetic.' },
    { label: 'Marathi Script', instruction: 'Convert the context into natural, spoken Marathi script.' }
];

interface ReaderProps {
    onUsage: () => void;
}

const Reader: React.FC<ReaderProps> = ({ onUsage }) => {
    const [text, setText] = useState<string>('');
    const [aiInstruction, setAiInstruction] = useState<string>('');
    const [language, setLanguage] = useState<string>('English');
    const [selectedVoice, setSelectedVoice] = useState<string>(MALE_VOICES[0].id);
    const [selectedTone, setSelectedTone] = useState<string>(MALE_VOICES[0].tones[0]);

    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [isRestructuring, setIsRestructuring] = useState<boolean>(false);
    const [isPreviewing, setIsPreviewing] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);
    const [audioData, setAudioData] = useState<string | null>(null);
    const [isEditing, setIsEditing] = useState<boolean>(true);

    const languages = ['English', 'Marathi', 'Hindi'];

    // Persistence Logic
    useEffect(() => {
        const savedUser = localStorage.getItem('active_user');
        if (savedUser) {
            const { email } = JSON.parse(savedUser);
            const savedSettings = localStorage.getItem(`tts_prefs_male_${email}`);
            if (savedSettings) {
                const prefs = JSON.parse(savedSettings);
                setLanguage(prefs.language || 'English');
                setSelectedVoice(prefs.voice || MALE_VOICES[0].id);
                setSelectedTone(prefs.tone || MALE_VOICES[0].tones[0]);
            }
        }
    }, []);

    const savePreferences = (voice: string, tone: string, lang: string) => {
        const savedUser = localStorage.getItem('active_user');
        if (savedUser) {
            const { email } = JSON.parse(savedUser);
            localStorage.setItem(`tts_prefs_male_${email}`, JSON.stringify({ language: lang, voice, tone }));
        }
    };

    const handleVoiceSelect = (vId: string) => {
        setSelectedVoice(vId);
        const voice = MALE_VOICES.find(v => v.id === vId);
        if (voice && !voice.tones.includes(selectedTone)) {
            setSelectedTone(voice.tones[0]);
        }
    };

    const handleRestructure = async (customInstruction?: string) => {
        const finalInstruction = customInstruction || aiInstruction;
        if (!text.trim() || !finalInstruction.trim()) return;

        setIsRestructuring(true);
        setError(null);
        try {
            const newText = await restructureText(text, finalInstruction);
            setText(newText);
            setAiInstruction('');
        } catch (err) {
            setError("AI Restructuring failed. Please try again.");
        } finally {
            setIsRestructuring(false);
        }
    };

    const handleAudition = async (vId: string, tName: string) => {
        setIsPreviewing(`${vId}-${tName}`);
        setError(null);
        try {
            const sampleText = language === 'English' 
                ? `Test. This is my ${tName} voice.`
                : language === 'Marathi' 
                    ? `चाचणी. हा माझा ${tName} आवाज आहे.`
                    : `परीक्षण। यह मेरी ${tName} आवाज़ है।`;

            const base64Audio = await textToSpeech(sampleText, language, tName, vId);
            await playAudio(base64Audio);
        } catch (err) {
            setError("Audition failed.");
        } finally {
            setIsPreviewing(null);
        }
    };

    const handleGenerateAudio = async () => {
        if (!text.trim()) {
            setError('Please enter some text.');
            return;
        }
        setIsLoading(true);
        setError(null);

        try {
            const base64Audio = await textToSpeech(text, language, selectedTone, selectedVoice);
            setAudioData(base64Audio);
            savePreferences(selectedVoice, selectedTone, language);
            setIsEditing(false);
            onUsage();
        } catch (err) {
            setError(err instanceof Error ? err.message : "Generation failed.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleDownload = () => {
        if (!audioData) return;
        try {
            const binary = atob(audioData);
            const bytes = new Uint8Array(binary.length);
            for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
            const wavBlob = createWavFile(bytes, 24000, 1, 16); 
            const url = URL.createObjectURL(wavBlob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `male-tts-${selectedVoice}-${selectedTone}.wav`;
            a.click();
            URL.revokeObjectURL(url);
        } catch (err) {
            setError("Download failed.");
        }
    };

    return (
        <div className="w-full flex flex-col gap-6 animate-pop-in max-w-4xl mx-auto">
            {/* Action Bar */}
            <div className="flex items-center justify-between px-2">
                <div className="flex items-center gap-2">
                    <h2 className="text-xl font-black text-textMain tracking-tighter uppercase italic">Male Voice Studio</h2>
                    <span className="text-[10px] px-2 py-0.5 bg-primary/10 text-primary border border-primary/20 rounded-full font-bold uppercase">v2.0</span>
                </div>
                {audioData && (
                    <button 
                        onClick={() => setIsEditing(!isEditing)} 
                        className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${isEditing ? 'bg-primary text-white border-primary' : 'bg-surface text-textSub border-border'}`}
                    >
                        {isEditing ? 'Viewing Mastered' : 'Edit Script & Voice'}
                    </button>
                )}
            </div>

            {isEditing && (
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 transition-all">
                    {/* Left Column: Voice Selection */}
                    <div className="lg:col-span-5 flex flex-col gap-4">
                        <div className="bg-surface p-5 rounded-2xl border border-border shadow-xl">
                            <label className="text-[10px] uppercase font-black text-textMuted mb-4 block tracking-widest">Select Persona</label>
                            <div className="flex flex-col gap-3">
                                {MALE_VOICES.map(v => (
                                    <div 
                                        key={v.id}
                                        onClick={() => handleVoiceSelect(v.id)}
                                        className={`p-4 rounded-xl border-2 transition-all cursor-pointer ${selectedVoice === v.id ? 'bg-primary/10 border-primary shadow-lg shadow-primary/10' : 'bg-black/20 border-transparent hover:border-textSub'}`}
                                    >
                                        <div className="flex justify-between items-start mb-1">
                                            <span className={`font-black text-lg ${selectedVoice === v.id ? 'text-primary' : 'text-textMain'}`}>{v.name}</span>
                                            {selectedVoice === v.id && <div className="w-2 h-2 bg-primary rounded-full animate-pulse"></div>}
                                        </div>
                                        <p className="text-xs text-textSub leading-tight mb-3">{v.description}</p>

                                        <div className="flex flex-wrap gap-2">
                                            {v.tones.map(t => (
                                                <button
                                                    key={t}
                                                    onClick={(e) => { e.stopPropagation(); setSelectedTone(t); setSelectedVoice(v.id); }}
                                                    className={`px-3 py-1.5 rounded-lg text-[10px] font-bold transition-all flex items-center gap-2 ${selectedVoice === v.id && selectedTone === t ? 'bg-primary text-white' : 'bg-black/30 text-textMuted hover:text-textMain'}`}
                                                >
                                                    {t}
                                                    <div 
                                                        onClick={(e) => { e.stopPropagation(); handleAudition(v.id, t); }}
                                                        className={`p-1 rounded-full ${isPreviewing === `${v.id}-${t}` ? 'bg-white text-primary' : 'bg-white/10 hover:bg-white/30'}`}
                                                    >
                                                        {isPreviewing === `${v.id}-${t}` ? <SpinnerIcon /> : <PlayIcon className="w-2 h-2" />}
                                                    </div>
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>

                        <div className="bg-surface p-5 rounded-2xl border border-border">
                            <label className="text-[10px] uppercase font-black text-textMuted mb-3 block tracking-widest">Language Context</label>
                            <div className="grid grid-cols-3 gap-2">
                                {languages.map(lang => (
                                    <button
                                        key={lang}
                                        onClick={() => setLanguage(lang)}
                                        className={`py-2 rounded-xl text-xs font-bold border transition-all ${language === lang ? 'bg-accent/20 border-accent text-accent' : 'bg-black/20 border-transparent text-textSub hover:bg-black/30'}`}
                                    >
                                        {lang}
                                    </button>
                                ))}
                            </div>
                        </div>
                    </div>

                    {/* Right Column: AI Script Editor */}
                    <div className="lg:col-span-7 flex flex-col gap-4">
                        <div className="bg-surface p-1 rounded-3xl border border-border shadow-2xl relative overflow-hidden group">
                            <textarea
                                value={text}
                                onChange={(e) => setText(e.target.value)}
                                placeholder={`Type your ${language} content here...`}
                                className="w-full h-64 p-6 bg-transparent text-textMain text-xl border-none focus:ring-0 resize-none placeholder-textMuted transition-all leading-relaxed"
                                disabled={isLoading || isRestructuring}
                            />
                            <div className="absolute bottom-4 left-6 flex items-center gap-3">
                                <span className="text-[10px] font-mono text-textMuted uppercase tracking-tighter">{text.length} CHARACTERS</span>
                            </div>
                        </div>

                        {/* AI Smart Assistant Area */}
                        {text.length > 5 && (
                            <div className="animate-slide-fade-in space-y-3">
                                <div className="flex items-center gap-2 px-2">
                                    <SparklesIcon className="w-4 h-4 text-secondary" />
                                    <span className="text-[10px] font-black uppercase tracking-widest text-textSub">AI Magic Assistant</span>
                                </div>

                                {/* Presets */}
                                <div className="flex flex-wrap gap-2 px-1">
                                    {AI_PRESETS.map((preset) => (
                                        <button
                                            key={preset.label}
                                            onClick={() => handleRestructure(preset.instruction)}
                                            disabled={isRestructuring}
                                            className="px-3 py-2 bg-secondary/10 border border-secondary/20 rounded-xl text-[10px] font-bold text-secondary hover:bg-secondary/20 transition-all flex items-center gap-2"
                                        >
                                            {preset.label}
                                        </button>
                                    ))}
                                </div>

                                {/* Custom Instruction Input */}
                                <div className={`flex gap-2 items-center bg-surface p-2 rounded-2xl border transition-all shadow-lg ${isRestructuring ? 'border-secondary animate-pulse' : 'border-border focus-within:border-secondary'}`}>
                                    <div className="pl-3 text-secondary">
                                        <SparklesIcon className="w-5 h-5" />
                                    </div>
                                    <input 
                                        type="text"
                                        value={aiInstruction}
                                        onChange={(e) => setAiInstruction(e.target.value)}
                                        placeholder="Give a custom instruction to rewrite all text..."
                                        className="flex-1 bg-transparent border-none focus:ring-0 text-sm text-textMain placeholder-textMuted py-2"
                                        disabled={isRestructuring || isLoading}
                                        onKeyDown={(e) => e.key === 'Enter' && handleRestructure()}
                                    />
                                    <button 
                                        onClick={() => handleRestructure()}
                                        disabled={!aiInstruction.trim() || isRestructuring || isLoading}
                                        className="px-5 py-2.5 bg-secondary text-white rounded-xl text-xs font-black uppercase tracking-tight hover:opacity-90 disabled:opacity-30 disabled:cursor-not-allowed transition-all flex items-center gap-2"
                                    >
                                        {isRestructuring ? <SpinnerIcon /> : 'Rewrite'}
                                    </button>
                                </div>
                            </div>
                        )}

                        <button
                            onClick={handleGenerateAudio}
                            disabled={isLoading || isRestructuring || !text.trim()}
                            className={`w-full py-5 rounded-2xl font-black text-xl transition-all transform flex items-center justify-center gap-4 shadow-xl border border-white/5 ${isLoading ? 'bg-surface text-textSub cursor-wait' : 'bg-gradient-to-r from-primary to-accent text-white hover:scale-[1.01] active:scale-95'}`}
                        >
                            {isLoading ? (
                                <>
                                    <SpinnerIcon /> 
                                    <span className="animate-pulse">Synthesizing Audio...</span>
                                </>
                            ) : audioData ? 'Re-generate Speech' : 'Generate Studio Speech'}
                        </button>
                        <p className="text-[10px] text-center text-textMuted uppercase tracking-widest opacity-50">AI Assistant is optional • Audio generation follows edits</p>
                    </div>
                </div>
            )}

            {error && (
                <div className="bg-red-900/40 border border-red-500 text-red-300 p-4 rounded-2xl text-center text-sm animate-pop-in">
                    {error}
                </div>
            )}

            {audioData && !isLoading && !isEditing && (
                <div className="w-full bg-surface rounded-3xl p-10 border border-primary/30 shadow-2xl animate-slide-fade-in flex flex-col items-center text-center gap-8 relative overflow-hidden group">
                    <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-primary via-secondary to-accent group-hover:h-2 transition-all"></div>

                    <div className="flex flex-col gap-2">
                        <div className="px-3 py-1 bg-primary/10 border border-primary/20 rounded-full text-[10px] font-black text-primary uppercase tracking-widest w-fit mx-auto mb-2">
                            Mastering Complete
                        </div>
                        <h3 className="text-3xl font-black text-textMain tracking-tight uppercase">
                            {MALE_VOICES.find(v => v.id === selectedVoice)?.name} ({selectedTone})
                        </h3>
                        <p className="text-sm text-textSub italic max-w-lg line-clamp-2 opacity-60">"{text}"</p>
                    </div>

                    <div className="flex items-center gap-6">
                        <button 
                            onClick={() => playAudio(audioData)} 
                            className="w-24 h-24 bg-primary text-white rounded-full flex items-center justify-center hover:scale-110 shadow-2xl shadow-primary/40 transition-all focus:outline-none"
                        >
                            <PlayIcon className="w-10 h-10" />
                        </button>
                        <button 
                            onClick={handleDownload} 
