                                </div>
                                <div className="flex gap-2">
                                    <button onClick={() => togglePermission(u, 'mcq')} className={`px-2 py-1 text-[10px] font-bold rounded-lg border transition-all ${u.permissions.mcq ? 'bg-primary text-white border-primary' : 'bg-black/40 text-textSub border-border'}`}>MCQ</button>
