                                    <button onClick={() => togglePermission(u, 'video')} className={`px-2 py-1 text-[10px] font-bold rounded-lg border transition-all ${u.permissions.video ? 'bg-primary text-white border-primary' : 'bg-black/40 text-textSub border-border'}`}>Animation</button>
                                </div>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
        </div>
