const createWavFile = (pcmData: Uint8Array, sampleRate: number, numChannels: number, bitsPerSample: number): Blob => {
    const dataSize = pcmData.length;
    const buffer = new ArrayBuffer(44 + dataSize);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => {
        for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + dataSize, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, numChannels, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * numChannels * (bitsPerSample / 8), true);
    view.setUint16(32, numChannels * (bitsPerSample / 8), true);
    view.setUint16(34, bitsPerSample, true);
    writeString(view, 36, 'data');
    view.setUint32(40, dataSize, true);
    new Uint8Array(buffer, 44).set(pcmData);
    return new Blob([buffer], { type: 'audio/wav' });
};

interface VoiceOption {
    id: string;
    name: string;
    description: string;
    tones: string[];
}

const MALE_VOICES: VoiceOption[] = [
    { id: 'Puck', name: 'Alpha', description: 'Bright, youthful, and vibrant.', tones: ['Energetic', 'Casual', 'Friendly'] },
    { id: 'Charon', name: 'Bravo', description: 'Deep, steady, and professional.', tones: ['Authoritative', 'Formal', 'Calm'] },
    { id: 'Fenrir', name: 'Delta', description: 'Mature, gritty, and wise.', tones: ['Narrative', 'Intense', 'Soft'] }
];

const AI_PRESETS = [
    { label: 'Fix Grammar', instruction: 'Correct all grammar and punctuation errors while keeping the meaning identical.' },
    { label: 'Summarize', instruction: 'Keep the core meaning but make the text significantly more concise.' },
    { label: 'More Professional', instruction: 'Rewrite this to sound more formal, professional, and authoritative.' },
    { label: 'Add Excitement', instruction: 'Make the tone more enthusiastic and energetic.' }
];

interface ReaderProps {
    onUsage: () => void;
}

const Reader: React.FC<ReaderProps> = ({ onUsage }) => {
    const [text, setText] = useState<string>('');
    const [aiInstruction, setAiInstruction] = useState<string>('');
    const [language, setLanguage] = useState<string>('English');
    const [selectedVoice, setSelectedVoice] = useState<string>(MALE_VOICES[0].id);
    const [selectedTone, setSelectedTone] = useState<string>(MALE_VOICES[0].tones[0]);
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [isRestructuring, setIsRestructuring] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [audioData, setAudioData] = useState<string | null>(null);
    const [isEditing, setIsEditing] = useState<boolean>(true);

    const handleRestructure = async (customInstruction?: string) => {
        const finalInstruction = customInstruction || aiInstruction;
        if (!text.trim() || !finalInstruction.trim()) return;
        setIsRestructuring(true);
        setError(null);
        try {
            const newText = await restructureText(text, finalInstruction);
            setText(newText);
            setAiInstruction('');
        } catch (err) {
            setError("AI Restructuring failed.");
        } finally {
            setIsRestructuring(false);
        }
    };

    const handleGenerateAudio = async () => {
        if (!text.trim()) return;
        setIsLoading(true);
        setError(null);
        try {
            const base64Audio = await textToSpeech(text, language, selectedTone, selectedVoice);
            setAudioData(base64Audio);
            setIsEditing(false);
            onUsage();
        } catch (err: any) {
            setError(err.message || "Generation failed.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleDownload = () => {
        if (!audioData) return;
        const binary = atob(audioData);
        const bytes = new Uint8Array(binary.length);
        for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
        const wavBlob = createWavFile(bytes, 24000, 1, 16);
        const url = URL.createObjectURL(wavBlob);

        // Dynamic filename based on the starting word of the script
        const firstWord = text.trim().split(' ')[0].replace(/[^a-zA-Z0-9]/g, '') || 'audio';

        const a = document.createElement('a');
        a.href = url;
        a.download = `${firstWord}-${selectedVoice}.wav`;
        a.click();
        URL.revokeObjectURL(url);
    };

    return (
        <div className="w-full flex flex-col gap-6 animate-pop-in max-w-4xl mx-auto">
            <div className="flex items-center justify-between px-2">
                <h2 className="text-xl font-black text-textMain tracking-tighter uppercase italic">Male Voice Studio</h2>
                {audioData && <button onClick={() => setIsEditing(!isEditing)} className={`px-4 py-2 rounded-xl text-xs font-bold border ${isEditing ? 'bg-primary text-white border-primary' : 'bg-surface text-textSub'}`}>{isEditing ? 'View Master' : 'Edit Script'}</button>}
            </div>

            {isEditing && (
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
                    <div className="lg:col-span-5 flex flex-col gap-4">
                        <div className="bg-surface p-5 rounded-2xl border border-border shadow-xl">
                            <label className="text-[10px] uppercase font-black text-textMuted mb-4 block tracking-widest">Voice Persona</label>
                            <div className="flex flex-col gap-3">
                                {MALE_VOICES.map(v => (
                                    <div key={v.id} onClick={() => setSelectedVoice(v.id)} className={`p-4 rounded-xl border-2 cursor-pointer transition-all ${selectedVoice === v.id ? 'bg-primary/10 border-primary shadow-lg shadow-primary/10' : 'bg-black/20 border-transparent hover:border-textSub'}`}>
                                        <div className="flex justify-between items-start mb-1"><span className={`font-black text-lg ${selectedVoice === v.id ? 'text-primary' : 'text-textMain'}`}>{v.name}</span></div>
                                        <p className="text-xs text-textSub leading-tight mb-3">{v.description}</p>
                                        <div className="flex flex-wrap gap-2">{v.tones.map(t => <button key={t} onClick={(e) => { e.stopPropagation(); setSelectedTone(t); setSelectedVoice(v.id); }} className={`px-3 py-1.5 rounded-lg text-[10px] font-bold transition-all ${selectedVoice === v.id && selectedTone === t ? 'bg-primary text-white' : 'bg-black/30 text-textMuted'}`}>{t}</button>)}</div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>

                    <div className="lg:col-span-7 flex flex-col gap-4">
                        <div className="bg-surface p-1 rounded-3xl border border-border shadow-2xl relative">
                            <textarea value={text} onChange={(e) => setText(e.target.value)} placeholder="Type script here..." className="w-full h-64 p-6 bg-transparent text-textMain text-xl border-none focus:ring-0 resize-none placeholder-textMuted leading-relaxed" disabled={isLoading || isRestructuring} />
                            <div className="absolute bottom-4 left-6 text-[10px] font-mono text-textMuted uppercase">{text.length} CHARS</div>
                        </div>

                        {text.length > 5 && (
                            <div className="animate-slide-fade-in space-y-3">
                                <div className="flex items-center gap-2 px-2"><SparklesIcon className="w-4 h-4 text-secondary" /><span className="text-[10px] font-black uppercase tracking-widest text-textSub">AI Smart Assistant</span></div>
                                <div className="flex flex-wrap gap-2">{AI_PRESETS.map((p) => <button key={p.label} onClick={() => handleRestructure(p.instruction)} disabled={isRestructuring} className="px-3 py-2 bg-secondary/10 border border-secondary/20 rounded-xl text-[10px] font-bold text-secondary">{p.label}</button>)}</div>
                                <div className={`flex gap-2 items-center bg-surface p-2 rounded-2xl border transition-all ${isRestructuring ? 'border-secondary animate-pulse' : 'border-border'}`}>
                                    <div className="pl-3 text-secondary"><SparklesIcon className="w-5 h-5" /></div>
                                    <input type="text" value={aiInstruction} onChange={(e) => setAiInstruction(e.target.value)} placeholder="Instruction: e.g. 'Make it more professional'" className="flex-1 bg-transparent border-none focus:ring-0 text-sm text-textMain placeholder-textMuted py-2" onKeyDown={(e) => e.key === 'Enter' && handleRestructure()} />
                                    <button onClick={() => handleRestructure()} disabled={!aiInstruction.trim() || isRestructuring} className="px-5 py-2.5 bg-secondary text-white rounded-xl text-xs font-black uppercase tracking-tight">{isRestructuring ? <SpinnerIcon /> : 'Edit'}</button>
                                </div>
                            </div>
                        )}

                        <button onClick={handleGenerateAudio} disabled={isLoading || isRestructuring || !text.trim()} className={`w-full py-5 rounded-2xl font-black text-xl transition-all shadow-xl ${isLoading ? 'bg-surface text-textSub cursor-wait' : 'bg-gradient-to-r from-primary to-accent text-white hover:scale-[1.01]'}`}>{isLoading ? <><SpinnerIcon /><span>Synthesizing...</span></> : 'Generate Speech'}</button>
                    </div>
                </div>
            )}

            {error && <div className="bg-red-900/40 border border-red-500 text-red-300 p-4 rounded-2xl text-center text-sm">{error}</div>}

            {audioData && !isLoading && !isEditing && (
                <div className="w-full bg-surface rounded-3xl p-10 border border-primary/30 shadow-2xl animate-slide-fade-in flex flex-col items-center text-center gap-8 relative overflow-hidden group">
                    <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-primary via-secondary to-accent"></div>
                    <div className="flex flex-col gap-2">
                        <div className="px-3 py-1 bg-primary/10 border border-primary/20 rounded-full text-[10px] font-black text-primary uppercase tracking-widest w-fit mx-auto mb-2">Master Ready</div>
                        <h3 className="text-3xl font-black text-textMain tracking-tight uppercase">{MALE_VOICES.find(v => v.id === selectedVoice)?.name} ({selectedTone})</h3>
                        <p className="text-sm text-textSub italic max-w-lg line-clamp-2 opacity-60">"{text}"</p>
                    </div>
                    <div className="flex items-center gap-6">
                        <button onClick={() => playAudio(audioData)} className="w-24 h-24 bg-primary text-white rounded-full flex items-center justify-center hover:scale-110 shadow-2xl transition-all"><PlayIcon className="w-10 h-10" /></button>
                        <button onClick={handleDownload} className="flex items-center gap-3 px-10 py-5 bg-black/40 text-white font-black rounded-2xl hover:bg-black/60 transition-all border border-white/5 shadow-lg"><DownloadIcon /><span>Export WAV</span></button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Reader;

import React, { useState, useEffect, useRef } from 'react';
import { generateImageFrame } from '../services/geminiService';
import SpinnerIcon from './icons/SpinnerIcon';
import PlayIcon from './icons/PlayIcon';
import DownloadIcon from './icons/DownloadIcon';

interface AnimationToolProps {
  onUsage: () => void;
}

const AnimationTool: React.FC<AnimationToolProps> = ({ onUsage }) => {
  const [prompt, setPrompt] = useState('');
  const [style, setStyle] = useState('3D Render');
  const [frames, setFrames] = useState<string[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generationProgress, setGenerationProgress] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentFrameIndex, setCurrentFrameIndex] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [fps, setFps] = useState(4); 

  const styles = [
      '3D Render', 
      'Unreal Engine 5', 
      'Pixar Style', 
      'Cinematic', 
      'Cyberpunk', 
      'Realistic', 
      'Anime', 
      'Oil Painting', 
      'Claymation'
  ];

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationIntervalRef = useRef<number | null>(null);
  const TOTAL_FRAMES = 8; 

  const handleGenerate = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    setFrames([]);
    setError(null);
    setCurrentFrameIndex(0);
    setGenerationProgress(0);
    setIsPlaying(false);

    const newFrames: string[] = [];

    try {
        const frame1Base64 = await generateImageFrame(prompt, style);
        newFrames.push(`data:image/jpeg;base64,${frame1Base64}`);
        setFrames([...newFrames]);
        setGenerationProgress(1);

        let previousFrame = frame1Base64;
        for (let i = 1; i < TOTAL_FRAMES; i++) {
            const movementPrompt = `Continue the action: ${prompt}. Frame ${i + 1} of ${TOTAL_FRAMES}. Slight movement.`;
            const nextFrameBase64 = await generateImageFrame(movementPrompt, style, previousFrame);
            newFrames.push(`data:image/jpeg;base64,${nextFrameBase64}`);
            setFrames([...newFrames]);
            setGenerationProgress(i + 1);
            previousFrame = nextFrameBase64;
        }

        onUsage();
        setIsPlaying(true); 
    } catch (err: any) {
        setError("Failed to generate frames. Please try again.");
        console.error(err);
    } finally {
        setIsGenerating(false);
    }
  };

  useEffect(() => {
    if (isPlaying && frames.length > 0) {
       animationIntervalRef.current = window.setInterval(() => {
           setCurrentFrameIndex(prev => (prev + 1) % frames.length);
       }, 1000 / fps);
    } else {
        if (animationIntervalRef.current) {
            clearInterval(animationIntervalRef.current);
        }
    }
    return () => {
        if (animationIntervalRef.current) clearInterval(animationIntervalRef.current);
    };
  }, [isPlaying, frames, fps]);

  useEffect(() => {
      const canvas = canvasRef.current;
      if (canvas && frames.length > 0 && frames[currentFrameIndex]) {
          const ctx = canvas.getContext('2d');
          const img = new Image();
          img.onload = () => {
              const aspectRatio = img.width / img.height;
              canvas.height = canvas.width / aspectRatio;
              ctx?.clearRect(0, 0, canvas.width, canvas.height);
              ctx?.drawImage(img, 0, 0, canvas.width, canvas.height);
          };
          img.src = frames[currentFrameIndex];
      }
  }, [currentFrameIndex, frames]);

  const handleDownloadVideo = () => {
      const canvas = canvasRef.current;
      if (!canvas) return;

      const stream = (canvas as any).captureStream(30); 
      let mimeType = 'video/webm';
      if (MediaRecorder.isTypeSupported('video/webm;codecs=vp9')) {
          mimeType = 'video/webm;codecs=vp9';
      } else if (MediaRecorder.isTypeSupported('video/mp4')) {
          mimeType = 'video/mp4';
      }

      const mediaRecorder = new MediaRecorder(stream, { 
          mimeType,
          videoBitsPerSecond: 5000000 
      });

      const chunks: Blob[] = [];
      mediaRecorder.ondataavailable = (e) => {
          if (e.data.size > 0) chunks.push(e.data);
      };

      mediaRecorder.onstop = () => {
          const blob = new Blob(chunks, { type: mimeType });
          const url = URL.createObjectURL(blob) as string;

          // Dynamic filename based on the starting word of the prompt
          const firstWord = prompt.trim().split(' ')[0].replace(/[^a-zA-Z0-9]/g, '') || 'animation';

          const a = document.createElement('a');
          a.href = url;
          const ext = mimeType.includes('mp4') ? 'mp4' : 'webm';
          a.download = `${firstWord}-animation.${ext}`;
          document.body.appendChild(a);
          a.click();
          window.URL.revokeObjectURL(url);
          a.remove();
      };

      mediaRecorder.start();
      setIsPlaying(false); 
      let frame = 0;
      const recInterval = setInterval(() => {
          if (frame >= frames.length) {
              clearInterval(recInterval);
              mediaRecorder.stop();
              setIsPlaying(true); 
          } else {
             setCurrentFrameIndex(frame);
             frame++;
          }
      }, 1000 / fps);
  };

  return (
    <div className="w-full max-w-4xl mx-auto space-y-6">
        <div className="bg-surface p-6 rounded-2xl backdrop-blur-sm border border-border animate-pop-in shadow-xl">
            <div className="flex justify-between items-start mb-6">
                <div>
                    <h2 className="text-2xl font-bold text-textMain mb-1 flex items-center gap-2">
                        <span className="text-secondary">AI</span> Animation Studio
                    </h2>
                    <p className="text-textSub text-sm">Create high-fidelity sequential animations.</p>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
                <div className="md:col-span-2">
                    <label className="text-xs text-textSub font-bold mb-2 block uppercase tracking-wider">Animation Prompt</label>
                    <input 
                        type="text"
                        value={prompt}
                        onChange={e => setPrompt(e.target.value)}
                        placeholder="e.g. A futuristic city..."
                        className="w-full px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-2 focus:ring-secondary outline-none transition-all"
                        disabled={isGenerating}
                    />
                </div>
                <div>
                    <label className="text-xs text-textSub font-bold mb-2 block uppercase tracking-wider">Art Style</label>
                    <select 
                        value={style}
                        onChange={e => setStyle(e.target.value)}
                        className="w-full px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-2 focus:ring-secondary outline-none cursor-pointer transition-all"
                        disabled={isGenerating}
                    >
                        {styles.map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                </div>
            </div>

            <button 
                onClick={handleGenerate}
                disabled={isGenerating || !prompt}
                className={`w-full py-4 font-bold rounded-xl transition-all flex items-center justify-center gap-3 shadow-lg
                    ${isGenerating 
                        ? 'bg-surface border border-border text-textSub cursor-wait' 
                        : 'bg-gradient-to-r from-secondary to-primary text-white hover:scale-[1.01]'
                    }`}
            >
                {isGenerating ? <><SpinnerIcon /><span>Generating...</span></> : 'Generate Animation'}
            </button>
        </div>

        {frames.length > 0 && (
            <div className="bg-surface p-6 rounded-2xl backdrop-blur-sm border border-border animate-slide-fade-in flex flex-col items-center shadow-2xl">
                 <div className="relative w-full max-w-[600px] aspect-video bg-black rounded-xl overflow-hidden shadow-2xl border border-white/10 mb-6 group">
                     <canvas ref={canvasRef} className="w-full h-full object-contain" width={800} height={450} />
                 </div>
                 <div className="flex flex-col sm:flex-row items-center gap-6 w-full max-w-[600px]">
                     <button onClick={() => setIsPlaying(!isPlaying)} className={`flex-shrink-0 flex items-center justify-center w-14 h-14 rounded-full transition-all shadow-lg ${isPlaying ? 'bg-secondary text-white' : 'bg-white text-secondary'}`}>
                         {isPlaying ? <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"/></svg> : <PlayIcon />}
                     </button>
                     <div className="flex-1 w-full bg-black/20 px-6 py-3 rounded-2xl border border-border flex items-center gap-4">
                         <span className="text-xs text-textSub font-bold uppercase">Speed</span>
                         <input type="range" min="1" max="10" value={fps} onChange={e => setFps(parseInt(e.target.value))} className="flex-1 accent-secondary cursor-pointer h-2 bg-black/30 rounded-lg appearance-none" />
                         <span className="text-xs text-textMain font-mono w-12 text-right">{fps} FPS</span>
                     </div>
                     <button onClick={handleDownloadVideo} className="flex-shrink-0 p-4 text-textMain bg-primary/20 hover:bg-primary/40 rounded-full transition-all border border-primary/30">
                         <DownloadIcon />
                     </button>
                 </div>
            </div>
        )}
    </div>
  );
};

export default AnimationTool;

import React, { useState } from 'react';
import { generateVideoScript, generateVeoVideo, VideoScene } from '../services/videoService';
import SpinnerIcon from './icons/SpinnerIcon';
import VideoIcon from './icons/VideoIcon';
import PlayIcon from './icons/PlayIcon';
import DownloadIcon from './icons/DownloadIcon';

interface ProVideoMakerProps {
  onUsage: () => void;
}

const ProVideoMaker: React.FC<ProVideoMakerProps> = ({ onUsage }) => {
  const [topic, setTopic] = useState('');
  const [script, setScript] = useState<VideoScene[] | null>(null);
  const [isScripting, setIsScripting] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [statusMsg, setStatusMsg] = useState('');
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleCreateScript = async () => {
    if (!topic.trim()) return;
    setIsScripting(true);
    setError(null);
    try {
      const result = await generateVideoScript(topic);
      setScript(result);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsScripting(false);
    }
  };

  const handleGenerateVideo = async () => {
    if (!script) return;

    const hasKey = await (window as any).aistudio.hasSelectedApiKey();
    if (!hasKey) {
      await (window as any).aistudio.openSelectKey();
    }

    setIsGenerating(true);
    setError(null);
    setVideoUrl(null);

    const combinedPrompt = script.map(s => s.visual_prompt).join(" Then, ");

    try {
      const url = await generateVeoVideo(combinedPrompt, setStatusMsg);
      setVideoUrl(url);
      onUsage();
    } catch (err: any) {
      if (err.message === "API_KEY_EXPIRED") {
          setError("Your session expired. Please select your API key again.");
          await (window as any).aistudio.openSelectKey();
      } else {
          setError(err.message || "An error occurred during production.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="w-full max-w-4xl mx-auto space-y-6">
      <div className="bg-surface p-6 rounded-2xl backdrop-blur-sm border border-border shadow-xl">
        <h2 className="text-2xl font-bold text-textMain mb-4 flex items-center gap-2">
          <span className="text-primary">PRO</span> Video Director
        </h2>
        <div className="flex gap-3">
          <input
            type="text"
            value={topic}
            onChange={(e) => setTopic(e.target.value)}
            placeholder="Enter a topic..."
            className="flex-1 px-4 py-3 bg-black/30 border border-border rounded-xl text-textMain focus:ring-2 focus:ring-primary outline-none transition-all"
            disabled={isScripting || isGenerating}
          />
          <button
            onClick={handleCreateScript}
            disabled={isScripting || isGenerating || !topic.trim()}
            className="px-6 py-3 bg-primary text-white font-bold rounded-xl hover:bg-primary-hover transition-all"
          >
            {isScripting ? <SpinnerIcon /> : 'Draft Script'}
          </button>
        </div>
        {error && <p className="mt-4 text-red-400 text-sm bg-red-900/20 p-3 rounded-lg border border-red-500/30">{error}</p>}
      </div>

      {script && !isGenerating && !videoUrl && (
        <div className="bg-surface p-8 rounded-2xl border border-border animate-pop-in">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-xl font-bold text-accent uppercase tracking-widest">Storyboards</h3>
            <button
              onClick={handleGenerateVideo}
              className="px-8 py-3 bg-secondary text-white font-black rounded-full hover:scale-105 active:scale-95 transition-all shadow-lg shadow-secondary/20"
            >
              Start Production
            </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {script.map((scene, i) => (
              <div key={i} className="p-4 bg-black/20 border border-border rounded-xl flex flex-col gap-2">
                <div className="text-xs font-bold text-textSub uppercase">Scene {i + 1}</div>
                <p className="text-sm text-textMain italic">"{scene.visual_prompt}"</p>
              </div>
            ))}
          </div>
        </div>
      )}

      {isGenerating && (
        <div className="bg-surface p-12 rounded-2xl border border-border flex flex-col items-center justify-center text-center animate-pulse">
          <VideoIcon className="w-24 h-24 text-secondary mb-8" />
          <h3 className="text-2xl font-bold text-textMain mb-2">Generating Cinematic Video</h3>
          <p className="text-textSub mb-6">{statusMsg}</p>
        </div>
      )}

      {videoUrl && (
        <div className="bg-black p-4 rounded-3xl border border-border shadow-2xl animate-slide-fade-in overflow-hidden">
          <div className="relative aspect-video rounded-2xl overflow-hidden bg-zinc-900">
            <video src={videoUrl} className="w-full h-full object-contain" controls autoPlay loop />
          </div>
          <div className="mt-4 flex justify-between items-center px-2">
            <div>
              <h3 className="text-lg font-bold text-white">The Final Cut</h3>
            </div>
