                download={`${topic.trim().split(' ')[0].replace(/[^a-zA-Z0-9]/g, '') || 'production'}.mp4`}
                className="flex items-center gap-2 px-6 py-2 bg-white text-black font-bold rounded-full hover:bg-zinc-200 transition-colors"
              >
                <DownloadIcon />
                Download
              </a>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

