  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);

    // Simulate network request for authentication
    setTimeout(() => {
      const matchedAccount = users.find(
        account => account.email.toLowerCase() === email.trim().toLowerCase() && account.password === password
      );

      if (matchedAccount) {
        setIsLoading(false);
        onLogin({
            email: matchedAccount.email,
            name: matchedAccount.name,
            role: matchedAccount.role,
            permissions: matchedAccount.permissions // Ensure permissions are passed
        });
      } else {
        setIsLoading(false);
        setError('Invalid email or password.');
      }
    }, 1000);
  };

  return (
    <div className="w-full max-w-md mx-auto animate-slide-fade-in px-4">
