import { GoogleGenAI, Type, Modality } from "@google/genai";
import { QuestionData } from "../types";

const ttsCache = new Map<string, string>();

/**
 * Analyzes an image of a question using Gemini 3 Flash.
 */
export async function processQuestionImage(imageBase64: string): Promise<QuestionData> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imagePart = {
    inlineData: {
      mimeType: 'image/jpeg',
      data: imageBase64,
    },
  };

  const textPart = {
    text: `Analyze this image of a multiple-choice question. Return a JSON object with:
      1. "question": The question text (remove leading numbers like "1.").
      2. "options": Array of objects with "letter" (e.g., "A") and "text".
      3. "correctOption": The letter of the correct answer (indicated by bold text, checkmarks, or visual cues). If uncertain, default to the first option.`,
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [textPart, imagePart] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          options: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                letter: { type: Type.STRING },
                text: { type: Type.STRING },
              },
              required: ['letter', 'text'],
            },
          },
          correctOption: { type: Type.STRING },
        },
        required: ['question', 'options', 'correctOption'],
      },
    },
  });

  const jsonString = (response.text || "").trim();
  try {
    return JSON.parse(jsonString) as QuestionData;
  } catch (e) {
    console.error("Failed to parse JSON from Gemini:", jsonString);
    throw new Error("The AI response was not in the expected format.");
  }
}

/**
 * Uses Gemini 3 Flash to edit or rewrite text based on instructions.
 */
export async function restructureText(text: string, instruction: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    ROLE: PROFESSIONAL SCRIPT & SPEECH EDITOR.
    CONTEXT: The user is preparing text for Text-to-Speech generation.

    ORIGINAL TEXT: "${text}"
    USER INSTRUCTION: "${instruction}"

    OBJECTIVE: 
    1. Strictly follow the user instruction.
    2. Ensure the output is natural for spoken delivery.
    3. Maintain paragraph breaks if they exist.
    4. RETURN ONLY THE REWRITTEN TEXT. DO NOT include meta-talk, quotes, or explanations.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
  });

  const cleaned = response.text?.trim() || text;
  return cleaned.replace(/^["']|["']$/g, '');
}

/**
 * Internal TTS core logic.
 */
async function attemptTextToSpeech(text: string, language?: string, tone?: string, voiceName?: string): Promise<string> {
    const cacheKey = `${language || 'auto'}-${tone || 'neutral'}-${voiceName || 'Charon'}-${text}`;
    if (ttsCache.has(cacheKey)) {
        return ttsCache.get(cacheKey)!;
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    let speechInstruction = "Speak this text naturally and clearly";
    if (language === 'Marathi') {
        speechInstruction = "Speak this text in natural Marathi with authentic Maharashtrian intonation and precise male pronunciation";
    } else if (language === 'Hindi') {
        speechInstruction = "Speak this text in standard Hindi with natural male cadence and clear diction";
    }

    if (tone) {
        speechInstruction += `, using a ${tone.toLowerCase()} and highly expressive male delivery`;
    }

    const fullPrompt = `${speechInstruction}:\n\n${text}`;

    const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: fullPrompt }] }],
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: {
                    prebuiltVoiceConfig: { voiceName: (voiceName as any) || 'Charon' },
                },
            },
        },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("API returned no audio data.");

    ttsCache.set(cacheKey, base64Audio);
    return base64Audio;
}

/**
 * Public TTS service with automatic retries.
 */
export async function textToSpeech(text: string, language?: string, tone?: string, voiceName?: string, retries = 3, delay = 500): Promise<string> {
    try {
        return await attemptTextToSpeech(text, language, tone, voiceName);
    } catch (error) {
        if (retries > 0) {
            await new Promise(resolve => setTimeout(resolve, delay));
            return textToSpeech(text, language, tone, voiceName, retries - 1, delay * 2);
        } else {
            throw new Error("Failed to generate audio.");
        }
    }
}

/**
 * Generates an animation frame with visual continuity.
 */
export async function generateImageFrame(prompt: string, style: string, previousFrameBase64?: string): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const parts: any[] = [];
    const qualityBoosters = "8k resolution, highly detailed, cinematic lighting, masterpiece, professional render, sharp focus, high fidelity";

    if (previousFrameBase64) {
        const refinedPrompt = `Generate the next frame of an animation sequence. 
        ACTION: ${prompt}.
        CONSTRAINT: Maintain identical character design, background, and lighting. Only minor movement.
        STYLE: ${style}.
        QUALITY: ${qualityBoosters}.`;

        parts.push({ text: refinedPrompt });
        parts.push({
            inlineData: {
                mimeType: 'image/jpeg',
                data: previousFrameBase64
            }
        });
    } else {
        const refinedPrompt = `Generate a high-fidelity keyframe. 
        SCENE: ${prompt}.
        STYLE: ${style}.
        QUALITY: ${qualityBoosters}.`;

        parts.push({ text: refinedPrompt });
    }

    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts },
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData && part.inlineData.data) {
            return part.inlineData.data;
        }
    }

    throw new Error("No image data generated.");
}

