import { GoogleGenAI, Type, Modality } from "@google/genai";
import { QuestionData } from "../types";

const ttsCache = new Map<string, string>();

/**
 * Analyzes an image of a question using Gemini 3 Flash.
 */
export async function processQuestionImage(imageBase64: string): Promise<QuestionData> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imagePart = {
    inlineData: {
      mimeType: 'image/jpeg',
      data: imageBase64,
    },
  };

  const textPart = {
    text: `Analyze this image of a multiple-choice question. Return a JSON object with:
      1. "question": The question text.
      2. "options": Array of objects with "letter" (A, B, C, D) and "text".
      3. "correctOption": The letter of the correct answer.`,
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [textPart, imagePart] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          options: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                letter: { type: Type.STRING },
                text: { type: Type.STRING },
              },
              required: ['letter', 'text'],
            },
          },
          correctOption: { type: Type.STRING },
        },
        required: ['question', 'options', 'correctOption'],
      },
    },
  });

  try {
    return JSON.parse(response.text || "") as QuestionData;
  } catch (e) {
    throw new Error("The AI response was not in the expected format.");
  }
}

/**
 * Restructures text for natural spoken delivery.
 */
export async function restructureText(text: string, instruction: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Rewrite the following text based on this instruction: "${instruction}". Text: "${text}". RETURN ONLY THE REWRITTEN TEXT.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
  });

  return response.text?.trim() || text;
}

/**
 * High-quality Text to Speech.
 */
export async function textToSpeech(text: string, language?: string, tone?: string, voiceName?: string): Promise<string> {
    const cacheKey = `${language}-${tone}-${voiceName}-${text}`;
    if (ttsCache.has(cacheKey)) return ttsCache.get(cacheKey)!;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    let speechInstruction = "Speak this text naturally and clearly";
    if (language === 'Marathi') speechInstruction = "Speak this in natural Marathi";
    else if (language === 'Hindi') speechInstruction = "Speak this in standard Hindi";

    if (tone) speechInstruction += `, using a ${tone.toLowerCase()} tone`;

    const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `${speechInstruction}:\n\n${text}` }] }],
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: {
                    prebuiltVoiceConfig: { voiceName: (voiceName as any) || 'Charon' },
                },
            },
        },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("Audio generation failed.");

    ttsCache.set(cacheKey, base64Audio);
    return base64Audio;
}

/**
 * Generates an image frame for animation using the nano banana series model (gemini-2.5-flash-image).
 */
export async function generateImageFrame(prompt: string, style: string, previousFrameBase64?: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [
    { text: `Style: ${style}. Prompt: ${prompt}` }
  ];

  // If a previous frame is provided, use it as a reference for temporal consistency.
  if (previousFrameBase64) {
    parts.unshift({
      inlineData: {
        mimeType: 'image/jpeg',
        data: previousFrameBase64,
      },
    });
    parts[1].text = `Maintaining character and background consistency from the provided image, generate the next frame in the animation sequence. Action: ${prompt}`;
  } else {
    parts[0].text = `Generate an initial high-quality frame for an animation sequence. Style: ${style}. Subject: ${prompt}`;
  }

  // Use generateContent for nano banana series models as required.
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts },
  });

  // Iterate through parts to find the generated image data.
  const candidate = response.candidates?.[0];
  if (candidate?.content?.parts) {
    for (const part of candidate.content.parts) {
      if (part.inlineData?.data) {
        return part.inlineData.data;
      }
    }
  }

  throw new Error("Failed to generate animation frame image.");
}

