  const getHeaderContent = () => {
    switch(currentView) {
        case 'MCQ_READER': return { title: mcqReaderTitle, subtitle: '', logoSize: 'w-24 h-24', titleSize: 'text-3xl', subtitleSize: 'text-base', headerMargin: 'mb-4' };
