        if (!config.name || !config.slogan || config.images.length === 0) {
            setError("Please fill in all details and upload at least one image.");
            return;
        }
        setStep('GENERATING');
        setError(null);
        try {
            const data = await generatePoliticalPoster(config);
            setResultUrl(`data:image/png;base64,${data}`);
            setStep('RESULT');
            onUsage();
        } catch (err: any) {
            setError(err.message || "Failed to generate poster.");
            setStep('CONTENT');
        }
    };

    const reset = () => {
        setStep('SIZE');
        setResultUrl(null);
        setConfig({ ...config, images: [], name: '', slogan: '' });
    };

    return (
        <div className="w-full max-w-2xl mx-auto space-y-6 animate-slide-fade-in pb-10">
            {step === 'SIZE' && (
                <div className="bg-surface p-8 rounded-2xl border border-border shadow-xl text-center">
                    <h2 className="text-2xl font-bold text-textMain mb-6">Start New Campaign Project</h2>
                    <p className="text-textSub mb-8">Select the target size for your political poster</p>
                    <div className="grid grid-cols-2 gap-4">
                        {SIZES.map(s => (
                            <button 
                                key={s.id} 
                                onClick={() => { setConfig({ ...config, aspectRatio: s.id }); setStep('CONTENT'); }}
                                className="p-6 bg-black/20 border border-border rounded-xl hover:border-primary hover:bg-primary/5 transition-all group flex flex-col items-center gap-3"
                            >
                                <span className="text-3xl text-primary group-hover:scale-110 transition-transform">{s.icon}</span>
                                <span className="text-sm font-bold text-textMain">{s.label}</span>
                            </button>
                        ))}
                    </div>
                </div>
            )}

            {step === 'CONTENT' && (
                <div className="bg-surface p-8 rounded-2xl border border-border shadow-xl space-y-6">
                    <div className="flex justify-between items-center">
                        <h2 className="text-xl font-bold text-textMain">Campaign Details</h2>
                        <button onClick={() => setStep('SIZE')} className="text-xs text-textSub hover:text-textMain">Change Size ({config.aspectRatio})</button>
                    </div>

                    <div className="space-y-4">
                        <div>
                            <label className="text-[10px] uppercase font-black text-textMuted mb-1 block">Language</label>
                            <div className="flex gap-2">
                                {LANGUAGES.map(l => (
                                    <button 
                                        key={l} 
                                        onClick={() => setConfig({...config, language: l})}
                                        className={`flex-1 py-2 text-xs font-bold rounded-lg border transition-all ${config.language === l ? 'bg-primary border-primary text-white' : 'bg-black/20 border-border text-textSub'}`}
                                    >
                                        {l}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div>
                            <label className="text-[10px] uppercase font-black text-textMuted mb-1 block">Candidate Name</label>
                            <input 
                                type="text" 
                                value={config.name}
                                onChange={e => setConfig({...config, name: e.target.value})}
                                placeholder="e.g. Rahul Patil"
                                className="w-full px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-2 focus:ring-primary outline-none"
                            />
                        </div>

                        <div>
                            <label className="text-[10px] uppercase font-black text-textMuted mb-1 block">Slogan</label>
                            <textarea 
                                value={config.slogan}
                                onChange={e => setConfig({...config, slogan: e.target.value})}
                                placeholder="e.g. Together for Progress..."
                                className="w-full h-24 px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-2 focus:ring-primary outline-none resize-none"
                            />
                        </div>

                        <div>
                            <label className="text-[10px] uppercase font-black text-textMuted mb-1 block">Candidate Photos (Backgrounds will be auto-removed)</label>
                            <FileUpload onFileSelect={handleFiles} disabled={false} />
                            {config.images.length > 0 && (
                                <div className="mt-3 flex flex-wrap gap-2">
                                    {config.images.map((img, i) => (
                                        <div key={i} className="relative w-16 h-16 rounded-lg overflow-hidden border border-border group">
                                            <img src={`data:image/jpeg;base64,${img}`} className="w-full h-full object-cover" />
                                            <button 
                                                onClick={() => setConfig({...config, images: config.images.filter((_, idx) => idx !== i)})}
                                                className="absolute inset-0 bg-red-500/80 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                                            >
                                                <CloseIcon className="w-4 h-4 text-white" />
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>

                        <div>
                            <label className="text-[10px] uppercase font-black text-textMuted mb-1 block">Design Style</label>
                            <select 
                                value={config.style}
                                onChange={e => setConfig({...config, style: e.target.value})}
                                className="w-full px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain cursor-pointer"
                            >
                                {STYLES.map(s => <option key={s} value={s}>{s}</option>)}
                            </select>
                        </div>
                    </div>

                    {error && <p className="text-red-400 text-xs text-center">{error}</p>}

                    <button 
                        onClick={handleGenerate}
                        className="w-full py-4 bg-primary text-white font-black text-lg rounded-xl shadow-lg hover:scale-[1.01] active:scale-[0.99] transition-all"
                    >
                        Design Poster
                    </button>
                </div>
            )}

            {step === 'GENERATING' && (
                <div className="bg-surface p-16 rounded-2xl border border-border shadow-xl flex flex-col items-center text-center space-y-6">
                    <div className="w-20 h-20 relative">
                        <div className="absolute inset-0 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
                        <div className="absolute inset-4 border-4 border-secondary border-b-transparent rounded-full animate-spin-reverse"></div>
                    </div>
                    <div className="space-y-2">
                        <h2 className="text-2xl font-bold text-textMain">Creative Studio at Work</h2>
                        <p className="text-textSub italic">"Removing backgrounds and arranging layers..."</p>
                    </div>
                    <div className="w-full max-w-xs bg-black/20 h-1.5 rounded-full overflow-hidden">
                        <div className="h-full bg-primary animate-[loading_10s_ease-in-out_infinite]"></div>
                    </div>
                </div>
            )}

            {step === 'RESULT' && resultUrl && (
                <div className="bg-surface p-6 rounded-2xl border border-border shadow-2xl animate-pop-in space-y-6">
                    <div className="relative rounded-xl overflow-hidden shadow-inner bg-zinc-900 border border-white/5">
                        <img src={resultUrl} className="w-full h-auto mx-auto" alt="Generated Poster" />
                    </div>
                    <div className="flex gap-4">
                        <button onClick={reset} className="flex-1 py-4 bg-black/40 text-textSub font-bold rounded-xl hover:bg-black/60 transition-colors">Create Another</button>
                        <a 
                            href={resultUrl} 
                            download={`campaign-poster-${config.name}.png`}
                            className="flex-1 py-4 bg-primary text-white font-black rounded-xl flex items-center justify-center gap-2 hover:bg-primary-hover shadow-lg"
                        >
                            <DownloadIcon />
                            Download Project
                        </a>
                    </div>
                </div>
            )}

            <style>{`
                @keyframes loading {
                    0% { width: 0%; }
                    50% { width: 70%; }
                    100% { width: 95%; }
                }
                .animate-spin-reverse { animation: spin-reverse 1.5s linear infinite; }
            `}</style>
        </div>
    );
};

