          <div className="relative z-10 flex flex-col items-center text-center">
            <MCQIcon className="w-20 h-20 text-primary group-hover:text-accent transition-colors" />
            <h3 className="mt-4 text-2xl font-bold text-textMain">{mcqReaderTitle}</h3>
            <p className="mt-2 text-sm text-textSub">Extract questions from images.</p>
          </div>
        </div>
      )}

      {/* Option 2: Reader */}
      {reader && (
        <div
          onClick={onSelectReader}
          className="group relative p-6 bg-surface rounded-2xl backdrop-blur-sm border border-border cursor-pointer transition-all duration-300 hover:border-primary hover:scale-105 hover:shadow-2xl hover:shadow-primary/20"
        >
          <div className="relative z-10 flex flex-col items-center text-center">
            <ReaderIcon className="w-20 h-20 text-primary group-hover:text-accent transition-colors" />
            <h3 className="mt-4 text-2xl font-bold text-textMain">Reader</h3>
            <p className="mt-2 text-sm text-textSub">Type text to generate high-quality audio.</p>
          </div>
        </div>
      )}

      {/* Option 3: Poster Maker */}
      {poster && (
        <div
          onClick={onSelectPosterMaker}
          className="group relative p-6 bg-surface rounded-2xl backdrop-blur-sm border border-border cursor-pointer transition-all duration-300 hover:border-secondary hover:scale-105 hover:shadow-2xl hover:shadow-secondary/20"
        >
          <div className="relative z-10 flex flex-col items-center text-center">
            <ImageGenIcon className="w-20 h-20 text-secondary group-hover:text-accent transition-colors" />
            <h3 className="mt-4 text-2xl font-bold text-textMain">Poster Maker</h3>
            <p className="mt-2 text-sm text-textSub">Campaign posters in Marathi, Hindi & English.</p>
          </div>
        </div>
      )}

      {/* Option 4: Appearance */}
      <div
        onClick={onOpenSettings}
        className="group relative p-6 bg-surface rounded-2xl backdrop-blur-sm border border-border cursor-pointer transition-all duration-300 hover:border-accent hover:scale-105 hover:shadow-2xl hover:shadow-accent/20"
      >
        <div className="relative z-10 flex flex-col items-center text-center">
          <PaletteIcon className="w-20 h-20 text-accent group-hover:text-white transition-colors" />
          <h3 className="mt-4 text-2xl font-bold text-textMain">Appearance</h3>
          <p className="mt-2 text-sm text-textSub">Customize visuals.</p>
        </div>
      </div>

      {/* Admin Panel */}
      {isAdmin && (
        <div
            onClick={onSelectAdmin}
            className="group relative p-6 bg-surface rounded-2xl backdrop-blur-sm border border-secondary cursor-pointer transition-all duration-300 hover:border-accent hover:scale-105 hover:shadow-2xl hover:shadow-accent/20"
        >
            <div className="relative z-10 flex flex-col items-center text-center">
            <AdminIcon className="w-20 h-20 text-secondary group-hover:text-accent transition-colors" />
            <h3 className="mt-4 text-2xl font-bold text-textMain">Admin Panel</h3>
            <p className="mt-2 text-sm text-textSub">System status and user controls.</p>
            </div>
        </div>
      )}
    </div>
  );
};

export default HomeScreen;

import React, { useState } from 'react';
import { UserAccount, UserRole, AppTheme, ThemeCategory, UserPermissions } from '../types';
import TrashIcon from './icons/TrashIcon';
import PaletteIcon from './icons/PaletteIcon';

interface AdminDashboardProps {
  users: UserAccount[];
  onAddUser: (user: UserAccount) => void;
  onDeleteUser: (email: string) => void;
  onUpdatePermissions: (email: string, permissions: UserPermissions) => void;
  currentUserEmail: string;
  themes: AppTheme[];
  currentTheme: AppTheme;
  onSetTheme: (theme: AppTheme) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ users, onAddUser, onDeleteUser, onUpdatePermissions, currentUserEmail, themes, currentTheme, onSetTheme }) => {
  const [newUserEmail, setNewUserEmail] = useState('');
  const [newUserName, setNewUserName] = useState('');
  const [newUserPass, setNewUserPass] = useState('');
  const [newUserRole, setNewUserRole] = useState<UserRole>('USER');
  const [error, setError] = useState<string | null>(null);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    if (!newUserEmail || !newUserName || !newUserPass) {
      setError("All fields required");
      return;
    }
    onAddUser({
      email: newUserEmail,
      name: newUserName,
      password: newUserPass,
      role: newUserRole,
      permissions: { mcq: true, reader: true, video: true, poster: true },
      stats: { mcqGenerations: 0, ttsGenerations: 0, lastActive: 'Never' }
    });
    setNewUserEmail(''); setNewUserName(''); setNewUserPass('');
  };

  const togglePermission = (u: UserAccount, key: keyof UserPermissions) => {
    // Handle potential missing keys from old user objects
    const currentPermissions = { mcq: true, reader: true, video: true, poster: true, ...u.permissions };
    onUpdatePermissions(u.email, { ...currentPermissions, [key]: !currentPermissions[key] });
  };

  return (
    <div className="w-full max-w-4xl mx-auto space-y-8 pb-8 animate-pop-in">
        <div className="bg-surface p-6 rounded-2xl border border-border">
            <h3 className="text-textSub text-sm font-semibold uppercase tracking-wider mb-4 flex items-center gap-2">Theme Settings</h3>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 max-h-[200px] overflow-y-auto pr-2 custom-scrollbar">
                {themes.map((theme) => (
                    <button key={theme.id} onClick={() => onSetTheme(theme)} className={`p-3 rounded-xl border-2 transition-all ${currentTheme.id === theme.id ? 'border-primary bg-primary/10' : 'border-transparent bg-black/20 hover:border-textSub'}`}>
                        <span className="text-xs font-medium">{theme.name}</span>
                    </button>
                ))}
            </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <div className="bg-surface p-8 rounded-2xl border border-border">
                <h2 className="text-xl font-bold text-textMain mb-4">Add User</h2>
                <form onSubmit={handleAdd} className="space-y-4">
                    <input type="text" value={newUserName} onChange={e => setNewUserName(e.target.value)} className="w-full px-3 py-2 bg-black/20 border border-border rounded-lg text-textMain" placeholder="Name" />
                    <input type="email" value={newUserEmail} onChange={e => setNewUserEmail(e.target.value)} className="w-full px-3 py-2 bg-black/20 border border-border rounded-lg text-textMain" placeholder="Email" />
                    <input type="text" value={newUserPass} onChange={e => setNewUserPass(e.target.value)} className="w-full px-3 py-2 bg-black/20 border border-border rounded-lg text-textMain" placeholder="Password" />
                    <select value={newUserRole} onChange={e => setNewUserRole(e.target.value as UserRole)} className="w-full px-3 py-2 bg-black/20 border border-border rounded-lg text-textMain"><option value="USER">User</option><option value="ADMIN">Admin</option></select>
                    {error && <div className="text-red-400 text-sm">{error}</div>}
                    <button type="submit" className="w-full py-2 bg-primary text-white font-semibold rounded-lg">Add User</button>
                </form>
            </div>

            <div className="bg-surface p-8 rounded-2xl border border-border flex flex-col">
                <h2 className="text-xl font-bold text-textMain mb-4">Manage Access</h2>
                <div className="flex-1 overflow-y-auto max-h-[400px] pr-2 custom-scrollbar">
                    <ul className="space-y-3">
                        {users.map((u) => {
                            // Destructure with fallbacks for UI state
                            const p = { mcq: true, reader: true, video: true, poster: true, ...u.permissions };
                            return (
                                <li key={u.email} className="p-4 bg-black/20 rounded-xl border border-border space-y-3">
                                    <div className="flex justify-between items-start">
                                        <div>
                                            <div className="font-bold text-textMain">{u.name} {u.role === 'ADMIN' && <span className="text-[10px] bg-primary/20 text-primary px-2 rounded-full">ADMIN</span>}</div>
                                            <div className="text-xs text-textSub">{u.email}</div>
                                        </div>
                                        {u.email !== currentUserEmail && <button onClick={() => onDeleteUser(u.email)} className="text-red-400 p-1 hover:bg-red-400/10 rounded-full"><TrashIcon className="w-4 h-4" /></button>}
                                    </div>
                                    <div className="flex flex-wrap gap-2">
                                        <button onClick={() => togglePermission(u, 'mcq')} className={`px-2 py-1 text-[10px] font-bold rounded-lg border transition-all ${p.mcq ? 'bg-primary text-white border-primary' : 'bg-black/40 text-textSub border-border'}`}>MCQ</button>
                                        <button onClick={() => togglePermission(u, 'reader')} className={`px-2 py-1 text-[10px] font-bold rounded-lg border transition-all ${p.reader ? 'bg-primary text-white border-primary' : 'bg-black/40 text-textSub border-border'}`}>Reader</button>
                                        <button onClick={() => togglePermission(u, 'poster')} className={`px-2 py-1 text-[10px] font-bold rounded-lg border transition-all ${p.poster ? 'bg-secondary text-white border-secondary' : 'bg-black/40 text-textSub border-border'}`}>Poster</button>
                                    </div>
                                </li>
                            );
                        })}
                    </ul>
                </div>
            </div>
        </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState } from 'react';
import { generatePoliticalPoster, PosterConfig } from '../services/geminiService';
import { fileToBase64 } from '../utils/file';
import SpinnerIcon from './icons/SpinnerIcon';
import DownloadIcon from './icons/DownloadIcon';
import FileUpload from './FileUpload';
import CloseIcon from './icons/CloseIcon';

const SIZES = [
    { id: '1:1', label: 'Square (Social)', icon: '▢' },
    { id: '3:4', label: 'Portrait (Flyer)', icon: '▯' },
    { id: '4:3', label: 'Landscape (Web)', icon: '▭' },
    { id: '16:9', label: 'Banner (Ad)', icon: '▬' },
];

const STYLES = ['Modern & Clean', 'Traditional Political', 'Dynamic & Bold', 'Minimalist', 'High Contrast'];
const LANGUAGES = ['Marathi', 'Hindi', 'English'];

const PosterMaker: React.FC<{ onUsage: () => void }> = ({ onUsage }) => {
    const [step, setStep] = useState<'SIZE' | 'CONTENT' | 'GENERATING' | 'RESULT'>('SIZE');
    const [config, setConfig] = useState<PosterConfig>({
        name: '',
        slogan: '',
        language: 'Marathi',
        style: STYLES[0],
        aspectRatio: '3:4',
        images: []
    });
    const [resultUrl, setResultUrl] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);

    const handleFiles = async (files: FileList) => {
        const base64s = await Promise.all(Array.from(files).map(fileToBase64));
        setConfig(prev => ({ ...prev, images: [...prev.images, ...base64s] }));
    };

    const handleGenerate = async () => {
        if (!config.name || !config.slogan || config.images.length === 0) {
            setError("Please fill in all details and upload at least one image.");
            return;
        }
        setStep('GENERATING');
        setError(null);
        try {
            const data = await generatePoliticalPoster(config);
            setResultUrl(`data:image/png;base64,${data}`);
            setStep('RESULT');
            onUsage();
        } catch (err: any) {
            setError(err.message || "Failed to generate poster.");
            setStep('CONTENT');
        }
    };

    const reset = () => {
        setStep('SIZE');
        setResultUrl(null);
        setConfig({ ...config, images: [], name: '', slogan: '' });
    };

    return (
        <div className="w-full max-w-2xl mx-auto space-y-6 animate-slide-fade-in pb-10">
            {step === 'SIZE' && (
                <div className="bg-surface p-8 rounded-2xl border border-border shadow-xl text-center">
                    <h2 className="text-2xl font-bold text-textMain mb-6 text-glow">New Campaign Project</h2>
                    <p className="text-textSub mb-8">Select the target size for your political poster</p>
                    <div className="grid grid-cols-2 gap-4">
                        {SIZES.map(s => (
                            <button 
                                key={s.id} 
                                onClick={() => { setConfig({ ...config, aspectRatio: s.id }); setStep('CONTENT'); }}
                                className="p-6 bg-black/20 border border-border rounded-xl hover:border-primary hover:bg-primary/5 transition-all group flex flex-col items-center gap-3"
                            >
                                <span className="text-3xl text-primary group-hover:scale-110 transition-transform">{s.icon}</span>
                                <span className="text-sm font-bold text-textMain">{s.label}</span>
                            </button>
                        ))}
                    </div>
                </div>
            )}

            {step === 'CONTENT' && (
                <div className="bg-surface p-8 rounded-2xl border border-border shadow-xl space-y-6">
                    <div className="flex justify-between items-center">
                        <h2 className="text-xl font-bold text-textMain">Campaign Details</h2>
                        <button onClick={() => setStep('SIZE')} className="text-xs text-textSub hover:text-textMain px-2 py-1 bg-black/20 rounded border border-border">Change Size ({config.aspectRatio})</button>
                    </div>

                    <div className="space-y-4 text-left">
                        <div>
                            <label className="text-[10px] uppercase font-black text-textMuted mb-1 block">Slogan Language</label>
                            <div className="flex gap-2">
                                {LANGUAGES.map(l => (
                                    <button 
                                        key={l} 
                                        onClick={() => setConfig({...config, language: l})}
                                        className={`flex-1 py-2 text-xs font-bold rounded-lg border transition-all ${config.language === l ? 'bg-primary border-primary text-white shadow-glow-sm' : 'bg-black/20 border-border text-textSub'}`}
                                    >
                                        {l}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div>
                            <label className="text-[10px] uppercase font-black text-textMuted mb-1 block">Candidate Name</label>
                            <input 
                                type="text" 
                                value={config.name}
                                onChange={e => setConfig({...config, name: e.target.value})}
                                placeholder="e.g. Rahul Patil"
                                className="w-full px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-2 focus:ring-primary outline-none"
                            />
                        </div>

                        <div>
                            <label className="text-[10px] uppercase font-black text-textMuted mb-1 block">Slogan</label>
                            <textarea 
                                value={config.slogan}
                                onChange={e => setConfig({...config, slogan: e.target.value})}
                                placeholder="e.g. Together for Progress..."
                                className="w-full h-24 px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-2 focus:ring-primary outline-none resize-none"
                            />
                        </div>

                        <div>
                            <label className="text-[10px] uppercase font-black text-textMuted mb-1 block">Candidate Photos</label>
                            <p className="text-[10px] text-textMuted mb-2 italic">Backgrounds will be automatically removed</p>
                            <FileUpload onFileSelect={handleFiles} disabled={false} />
                            {config.images.length > 0 && (
                                <div className="mt-3 flex flex-wrap gap-2">
                                    {config.images.map((img, i) => (
                                        <div key={i} className="relative w-16 h-16 rounded-lg overflow-hidden border border-border group">
                                            <img src={`data:image/jpeg;base64,${img}`} className="w-full h-full object-cover" />
                                            <button 
                                                onClick={() => setConfig({...config, images: config.images.filter((_, idx) => idx !== i)})}
                                                className="absolute inset-0 bg-red-500/80 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                                            >
                                                <CloseIcon className="w-4 h-4 text-white" />
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>

                        <div>
                            <label className="text-[10px] uppercase font-black text-textMuted mb-1 block">Poster Style</label>
                            <select 
                                value={config.style}
                                onChange={e => setConfig({...config, style: e.target.value})}
                                className="w-full px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain cursor-pointer outline-none focus:ring-2 focus:ring-primary"
                            >
                                {STYLES.map(s => <option key={s} value={s} className="bg-background">{s}</option>)}
                            </select>
                        </div>
                    </div>

                    {error && <p className="text-red-400 text-xs text-center font-bold bg-red-500/10 p-2 rounded">{error}</p>}

                    <button 
                        onClick={handleGenerate}
                        className="w-full py-4 bg-primary text-white font-black text-lg rounded-xl shadow-lg hover:scale-[1.01] active:scale-[0.99] transition-all"
                    >
                        Design Campaign Poster
                    </button>
                </div>
            )}

            {step === 'GENERATING' && (
                <div className="bg-surface p-16 rounded-2xl border border-border shadow-xl flex flex-col items-center text-center space-y-6">
                    <div className="w-24 h-24 relative">
                        <div className="absolute inset-0 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
                        <div className="absolute inset-4 border-4 border-secondary border-b-transparent rounded-full animate-spin-reverse"></div>
                    </div>
                    <div className="space-y-2">
                        <h2 className="text-2xl font-bold text-textMain text-glow">Creative Studio Working</h2>
                        <p className="text-textSub italic">"Removing backgrounds, arranging layers, and rendering text..."</p>
                    </div>
                    <div className="w-full max-w-xs bg-black/20 h-2 rounded-full overflow-hidden">
                        <div className="h-full bg-primary animate-[loading_12s_ease-in-out_infinite]"></div>
                    </div>
                </div>
            )}

            {step === 'RESULT' && resultUrl && (
                <div className="bg-surface p-6 rounded-2xl border border-border shadow-2xl animate-pop-in space-y-6">
                    <div className="relative rounded-xl overflow-hidden shadow-inner bg-zinc-900 border border-white/5">
                        <img src={resultUrl} className="w-full h-auto mx-auto" alt="Generated Poster" />
                    </div>
                    <div className="flex gap-4">
                        <button onClick={reset} className="flex-1 py-4 bg-black/40 text-textSub font-bold rounded-xl hover:bg-black/60 transition-colors">Start New Project</button>
                        <a 
                            href={resultUrl} 
                            download={`campaign-poster-${config.name}.png`}
                            className="flex-1 py-4 bg-primary text-white font-black rounded-xl flex items-center justify-center gap-2 hover:bg-primary-hover shadow-lg shadow-primary/20"
                        >
                            <DownloadIcon />
                            Download Project
                        </a>
                    </div>
                </div>
            )}

            <style>{`
                @keyframes loading {
                    0% { width: 0%; }
                    50% { width: 75%; }
                    100% { width: 98%; }
                }
                .animate-spin-reverse { animation: spin-reverse 2s linear infinite; }
            `}</style>
        </div>
    );
};

export default PosterMaker;

