    ? { parts: [{ inlineData: { mimeType: 'image/jpeg', data: previousFrameBase64 } }, textPart] }
    : { parts: [textPart] };

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: contents,
  });

  // Find the image part in the response
  const imagePart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (imagePart?.inlineData?.data) {
    return imagePart.inlineData.data;
  }

  throw new Error("The AI failed to generate an image frame.");
}

/**
 * Generates a political campaign poster using Gemini image generation models.
 * Fixed missing export reported in PosterMaker.tsx.
 */
export async function generatePoliticalPoster(config: PosterConfig): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const textPart = {
    text: `Create a professional political campaign poster in ${config.style} style. 
    Language: ${config.language}. 
    Candidate Name: ${config.name}. 
    Slogan: ${config.slogan}. 
    Please remove the backgrounds from the provided candidate photos and integrate them naturally into a high-impact political design. 
    Ensure the text is clear, authoritative, and properly placed.`
  };

  const imageParts = config.images.map(img => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: img,
    }
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [...imageParts, textPart] },
    config: {
      imageConfig: {
        aspectRatio: config.aspectRatio as any,
      }
    }
  });

  // Find the image part in the response candidates by iterating through parts
  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return part.inlineData.data;
      }
    }
  }

  throw new Error("Failed to generate campaign poster.");
}

