const LANGUAGES = ['Marathi', 'Hindi', 'English'];

const PosterMaker: React.FC<{ onUsage: () => void }> = ({ onUsage }) => {
    const [step, setStep] = useState<'INPUT' | 'GENERATING' | 'RESULT'>('INPUT');

    // Form State
    const [candidateName, setCandidateName] = useState('');
    const [designation, setDesignation] = useState('');
    const [partyName, setPartyName] = useState('');
    const [theme, setTheme] = useState('');
    const [language, setLanguage] = useState('Marathi');
    const [images, setImages] = useState<string[]>([]);

    const [blueprint, setBlueprint] = useState<PosterBlueprint | null>(null);
    const [error, setError] = useState<string | null>(null);

    const handleFiles = async (files: FileList) => {
        const base64s = await Promise.all(Array.from(files).map(fileToBase64));
        setImages(prev => [...prev, ...base64s]);
    };

    const handleGenerate = async () => {
        if (!candidateName || !partyName || !theme) {
            setError("Please fill in the candidate name, party, and theme.");
            return;
        }
        setStep('GENERATING');
        setError(null);
        try {
            const result = await generatePosterBlueprint(
                candidateName,
                designation,
                partyName,
                images.length,
                language,
                theme
            );
            setBlueprint(result);
            setStep('RESULT');
            onUsage();
        } catch (err: any) {
            setError(err.message || "Failed to generate blueprint.");
            setStep('INPUT');
        }
    };

    const reset = () => {
        setStep('INPUT');
        setBlueprint(null);
        setImages([]);
        setCandidateName('');
        setDesignation('');
        setPartyName('');
        setTheme('');
    };

    // Helper to render layers for preview (Mocking Fabric.js behavior)
    const renderPreview = () => {
        if (!blueprint) return null;

        // Canvas dimensions
        const W = 1080;
        const H = 1350;

        return (
            <div 
                className="relative mx-auto overflow-hidden shadow-2xl rounded-sm bg-white" 
                style={{ 
                    width: '100%', 
                    paddingBottom: `${(H / W) * 100}%`, // Aspect Ratio
                    background: blueprint.background.color 
                }}
            >
                <div className="absolute inset-0">
                    {blueprint.layers.sort((a, b) => a.zIndex - b.zIndex).map((layer) => {
                        // Convert center coordinates to percentage
                        const left = (layer.x / W) * 100;
                        const top = (layer.y / H) * 100;

                        if (layer.type === 'text') {
                            return (
                                <div 
                                    key={layer.id}
                                    className="absolute transform -translate-x-1/2 -translate-y-1/2 text-center whitespace-nowrap"
                                    style={{
                                        left: `${left}%`,
                                        top: `${top}%`,
                                        fontFamily: layer.font || 'sans-serif',
                                        fontSize: `clamp(12px, ${layer.size ? layer.size / 3 : 20}px, 60px)`, // Scale text for responsiveness
                                        color: layer.color || '#000',
                                        opacity: layer.opacity || 1,
                                        zIndex: layer.zIndex
                                    }}
                                >
                                    {layer.content}
                                </div>
                            );
                        } else if (layer.type === 'image') {
                            // Try to map uploaded image to main_candidate
                            const imgSrc = (layer.id.includes('main') && images.length > 0) 
                                ? `data:image/jpeg;base64,${images[0]}` 
                                : null;

                            return (
                                <div 
                                    key={layer.id}
                                    className="absolute transform -translate-x-1/2 -translate-y-1/2 flex items-center justify-center border-2 border-dashed border-gray-400 bg-gray-100/50"
                                    style={{
                                        left: `${left}%`,
                                        top: `${top}%`,
                                        width: `${(layer.width || 400) / W * 100}%`,
                                        height: `${(layer.height || 400) / H * 100}%`,
                                        zIndex: layer.zIndex
                                    }}
                                >
                                    {imgSrc ? (
                                        <img src={imgSrc} className="w-full h-full object-contain" alt={layer.id} />
                                    ) : (
                                        <span className="text-xs text-gray-500 font-mono">{layer.placeholder || 'Image'}</span>
                                    )}
                                </div>
                            );
                        }
                        return null;
                    })}
                </div>
            </div>
        );
    };

