                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-4">
                            <div>
                                <label className="text-xs font-bold text-textSub uppercase tracking-wider mb-1 block">Candidate Name</label>
                                <input type="text" value={candidateName} onChange={e => setCandidateName(e.target.value)} className="w-full px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-2 focus:ring-secondary outline-none" placeholder="e.g. Rahul Patil" />
