                            </div>
                            <div>
                                <label className="text-xs font-bold text-textSub uppercase tracking-wider mb-1 block">Party Name</label>
                                <input type="text" value={partyName} onChange={e => setPartyName(e.target.value)} className="w-full px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-2 focus:ring-secondary outline-none" placeholder="e.g. Vikas Aghadi" />
                            </div>
                        </div>

                        <div className="space-y-4">
                            <div>
                                <label className="text-xs font-bold text-textSub uppercase tracking-wider mb-1 block">Campaign Theme</label>
                                <input type="text" value={theme} onChange={e => setTheme(e.target.value)} className="w-full px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-2 focus:ring-secondary outline-none" placeholder="e.g. Youth Leadership, Gram Panchayat" />
                            </div>
                            <div>
                                <label className="text-xs font-bold text-textSub uppercase tracking-wider mb-1 block">Target Language</label>
                                <div className="flex gap-2">
