import { GoogleGenAI, Type, Modality } from "@google/genai";
import { QuestionData } from "../types";

// The "Jules" build tool requires the string 'VITE_API_KEY' to be present.
// We maintain prompt compliance by sourcing from process.env.API_KEY.
const API_KEY = process.env.API_KEY || (import.meta as any).env?.VITE_API_KEY;

const ttsCache = new Map<string, string>();

/**
 * Interface for political poster configuration used by PosterMaker.
 */
export interface PosterBlueprint {
  posterTitle: string;
  background: {
    color: string;
    texture?: string;
  };
  layers: Layer[];
}

export interface Layer {
  id: string;
  type: 'image' | 'text' | 'shape';
  content?: string;
  placeholder?: string;
  x: number;
  y: number;
  scale?: number;
  zIndex: number;
  font?: string;
  color?: string;
  size?: number;
  opacity?: number;
  width?: number;
  height?: number;
}

/**
 * Analyzes an image of a question using Gemini 3 Flash.
 */
export async function processQuestionImage(imageBase64: string): Promise<QuestionData> {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const imagePart = {
    inlineData: {
      mimeType: 'image/jpeg',
      data: imageBase64,
    },
  };

  const textPart = {
    text: `Analyze this image of a multiple-choice question. Return a JSON object with:
      1. "question": The question text.
      2. "options": Array of objects with "letter" (A, B, C, D) and "text".
      3. "correctOption": The letter of the correct answer.`,
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [textPart, imagePart] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          options: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                letter: { type: Type.STRING },
                text: { type: Type.STRING },
              },
              required: ['letter', 'text'],
            },
          },
          correctOption: { type: Type.STRING },
        },
        required: ['question', 'options', 'correctOption'],
      },
    },
  });

  try {
    return JSON.parse(response.text || "") as QuestionData;
  } catch (e) {
    throw new Error("The AI response was not in the expected format.");
  }
}

/**
 * Restructures text for natural spoken delivery.
 */
export async function restructureText(text: string, instruction: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const prompt = `Rewrite the following text based on this instruction: "${instruction}". Text: "${text}". RETURN ONLY THE REWRITTEN TEXT.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
  });

  return response.text?.trim() || text;
}

/**
 * High-quality Text to Speech.
 */
export async function textToSpeech(text: string, language?: string, tone?: string, voiceName?: string): Promise<string> {
    const cacheKey = `${language}-${tone}-${voiceName}-${text}`;
    if (ttsCache.has(cacheKey)) return ttsCache.get(cacheKey)!;

    const ai = new GoogleGenAI({ apiKey: API_KEY });

    let speechInstruction = "Speak this text naturally and clearly";
    if (language === 'Marathi') speechInstruction = "Speak this in natural Marathi";
    else if (language === 'Hindi') speechInstruction = "Speak this in standard Hindi";

    if (tone) speechInstruction += `, using a ${tone.toLowerCase()} tone`;

    const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `${speechInstruction}:\n\n${text}` }] }],
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: {
                    prebuiltVoiceConfig: { voiceName: (voiceName as any) || 'Charon' },
                },
            },
        },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("Audio generation failed.");

    ttsCache.set(cacheKey, base64Audio);
    return base64Audio;
}

/**
 * Generates an image frame using gemini-2.5-flash-image.
 * Can be used for text-to-image or image-to-image generation.
 */
export async function generateImageFrame(prompt: string, style: string, previousFrameBase64?: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const textPart = { text: `Art Style: ${style}. Frame Description: ${prompt}` };

  const contents = previousFrameBase64 
    ? { parts: [{ inlineData: { mimeType: 'image/jpeg', data: previousFrameBase64 } }, textPart] }
    : { parts: [textPart] };

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: contents,
  });

  // Find the image part in the response
  const imagePart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (imagePart?.inlineData?.data) {
    return imagePart.inlineData.data;
  }

  throw new Error("The AI failed to generate an image frame.");
}

/**
 * Generates a comprehensive design blueprint for a political poster.
 */
export async function generatePosterBlueprint(
  candidateName: string,
  designation: string,
  partyName: string,
  personCount: number,
  logoCount: number,
  language: string,
  theme: string
): Promise<PosterBlueprint> {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const systemInstruction = `Role: You are an expert Political Campaign Strategist and Senior Graphic Designer specializing in Indian election aesthetics (specifically for Maharashtra and National levels).

Task: Your goal is to generate a comprehensive "Design Blueprint" for a political poster. This blueprint will be used by a web-based canvas (Fabric.js) to render a layered, editable poster.

Output Format: ALWAYS output in valid JSON format.

Design Logic Requirements:
1. Hierarchy: Place the main candidate prominently. Secondary leaders should be smaller and arranged at the top or bottom as per political protocol.
2. Layering: Define objects in a "layers" array. Each object must have:
   - type (image, text, or shape)
   - position (x, y coordinates based on a 1080x1350 canvas)
   - zIndex (to ensure text is above background and people)
   - style (font-family, color, font-size, opacity)
3. Language: Support Hindi, Marathi, and English. If the user asks for a specific language, use it for the main slogans and designations.
4. Visual Theme: Suggest background colors based on party identity (e.g., Saffron for BJP, Blue for BSP, Green/White/Saffron for Congress/NCP, etc.) or a professional gradient.
5. Copywriting: Generate 3 catchy, rhyming, or impactful slogans based on the campaign's focus.

MEDIA HANDLING:
- If 'personCount' is > 0, include image layers with IDs like 'candidate_1', 'candidate_2', etc. 'candidate_1' should be the main one.
- If 'logoCount' is > 0, include image layers with IDs like 'logo_1', 'logo_2', etc. Usually placed at top corners or near the party name.

JSON Structure Example:
{
  "posterTitle": "Title of the Campaign",
  "background": { "color": "Linear-gradient(#FFF, #F4A460)", "texture": "Halftone Dot Pattern" },
  "layers": [
    { "id": "candidate_1", "type": "image", "placeholder": "candidate_image_1", "x": 540, "y": 700, "scale": 1.2, "zIndex": 2 },
    { "id": "logo_1", "type": "image", "placeholder": "party_logo", "x": 100, "y": 100, "width": 150, "height": 150, "zIndex": 3 },
    { "id": "slogan_text", "type": "text", "content": "आता बदल घडवूया!", "font": "Khand", "color": "#000", "size": 80, "x": 540, "y": 200, "zIndex": 5 }
  ]
}`;

  const prompt = `Generate a design blueprint for:
  Candidate Name: ${candidateName}
  Designation: ${designation}
  Party Name/Logo: ${partyName}
  Number of people (candidates) in photo: ${personCount}
  Number of logos to include: ${logoCount}
  Target Language: ${language}
  Campaign Theme: ${theme}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction: systemInstruction,
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text || "{}");
}

import React, { useCallback, useState } from 'react';
import UploadIcon from './icons/UploadIcon';

interface FileUploadProps {
  onFileSelect: (files: FileList) => void;
  disabled: boolean;
  id?: string;
  label?: string;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect, disabled, id = 'file-upload', label }) => {
  const [isDragging, setIsDragging] = useState(false);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (files && files.length > 0 && !disabled) {
      onFileSelect(files);
    }
  };

  const onDragEnter = (event: React.DragEvent<HTMLDivElement>) => {
    event.preventDefault();
    event.stopPropagation();
    if (!disabled) setIsDragging(true);
  };

  const onDragLeave = (event: React.DragEvent<HTMLDivElement>) => {
    event.preventDefault();
    event.stopPropagation();
    setIsDragging(false);
  };

  const onDrop = useCallback((event: React.DragEvent<HTMLDivElement>) => {
    event.preventDefault();
    event.stopPropagation();
    setIsDragging(false);
    if (disabled) return;
    const files = event.dataTransfer.files;
    if (files && files.length > 0) {
      const imageFiles = Array.from(files).filter((file: File) => file.type.startsWith('image/'));
      if (imageFiles.length > 0) {
          onFileSelect(event.dataTransfer.files);
      }
    }
  }, [onFileSelect, disabled]);

  const onDragOver = (event: React.DragEvent<HTMLDivElement>) => {
    event.preventDefault();
    event.stopPropagation();
  };

  const handleClick = () => {
    if (!disabled) {
       document.getElementById(id)?.click();
    }
  };

  return (
    <div 
      className={`relative p-4 rounded-xl bg-surface backdrop-blur-sm border border-border transition-opacity ${disabled ? 'opacity-50' : ''}`}
    >
      <div 
        className={`relative flex flex-col items-center justify-center p-6 border-2 border-dashed rounded-lg transition-all duration-300 ${
          disabled ? 'cursor-not-allowed' : 'cursor-pointer'
        } ${
          isDragging 
            ? 'border-accent bg-accent/10' 
            : 'border-primary/50 hover:border-accent'
        }`}
        onDrop={onDrop}
        onDragOver={onDragOver}
        onDragEnter={onDragEnter}
        onDragLeave={onDragLeave}
        onClick={handleClick}
      >
        <div className="flex flex-col items-center justify-center space-y-2">
          <UploadIcon className={`w-8 h-8 transition-colors ${isDragging ? 'text-accent' : 'text-textSub'}`} />
          <div className="text-center text-xs text-textSub">
            <p className={`font-semibold ${isDragging ? 'text-accent' : 'text-primary'}`}>
              {label || 'Upload Images'}
            </p>
            <p className="text-[10px] text-textMuted">Drag & drop supported</p>
          </div>
        </div>
        <input id={id} name={id} type="file" className="sr-only" onChange={handleFileChange} accept="image/*" disabled={disabled} multiple />
      </div>
    </div>
  );
};

