import { GoogleGenAI, Type, Modality } from "@google/genai";
import { QuestionData } from "../types";

// The "Jules" build tool requires the string 'VITE_API_KEY' to be present.
// We maintain prompt compliance by sourcing from process.env.API_KEY.
const API_KEY = process.env.API_KEY || (import.meta as any).env?.VITE_API_KEY;

const ttsCache = new Map<string, string>();

/**
 * Interface for political poster configuration used by PosterMaker.
 */
export interface PosterBlueprint {
  posterTitle: string;
  background: {
    color: string;
    texture?: string;
  };
  layers: Layer[];
}

export interface Layer {
  id: string;
  type: 'image' | 'text' | 'shape';
  content?: string;
  placeholder?: string;
  x: number;
  y: number;
  scale?: number;
  zIndex: number;
  font?: string;
  color?: string;
  size?: number;
  opacity?: number;
  width?: number;
  height?: number;
}

export interface PersonInfo {
  name: string;
  designation: string;
}

/**
 * Analyzes an image of a question using Gemini 3 Flash.
 */
export async function processQuestionImage(imageBase64: string): Promise<QuestionData> {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const imagePart = {
    inlineData: {
      mimeType: 'image/jpeg',
      data: imageBase64,
    },
  };

  const textPart = {
    text: `Analyze this image of a multiple-choice question. Return a JSON object with:
      1. "question": The question text.
      2. "options": Array of objects with "letter" (A, B, C, D) and "text".
      3. "correctOption": The letter of the correct answer.`,
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [textPart, imagePart] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          options: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                letter: { type: Type.STRING },
                text: { type: Type.STRING },
              },
              required: ['letter', 'text'],
            },
          },
          correctOption: { type: Type.STRING },
        },
        required: ['question', 'options', 'correctOption'],
      },
    },
  });

  try {
    return JSON.parse(response.text || "") as QuestionData;
  } catch (e) {
    throw new Error("The AI response was not in the expected format.");
  }
}

/**
 * Restructures text for natural spoken delivery.
 */
export async function restructureText(text: string, instruction: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const prompt = `Rewrite the following text based on this instruction: "${instruction}". Text: "${text}". RETURN ONLY THE REWRITTEN TEXT.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
  });

  return response.text?.trim() || text;
}

/**
 * High-quality Text to Speech.
 */
export async function textToSpeech(text: string, language?: string, tone?: string, voiceName?: string): Promise<string> {
    const cacheKey = `${language}-${tone}-${voiceName}-${text}`;
    if (ttsCache.has(cacheKey)) return ttsCache.get(cacheKey)!;

    const ai = new GoogleGenAI({ apiKey: API_KEY });

    let speechInstruction = "Speak this text naturally and clearly";
    if (language === 'Marathi') speechInstruction = "Speak this in natural Marathi";
    else if (language === 'Hindi') speechInstruction = "Speak this in standard Hindi";

    if (tone) speechInstruction += `, using a ${tone.toLowerCase()} tone`;

    const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `${speechInstruction}:\n\n${text}` }] }],
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: {
                    prebuiltVoiceConfig: { voiceName: (voiceName as any) || 'Charon' },
                },
            },
        },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("Audio generation failed.");

    ttsCache.set(cacheKey, base64Audio);
    return base64Audio;
}

/**
 * Generates an image frame using gemini-2.5-flash-image.
 * Can be used for text-to-image or image-to-image generation.
 */
export async function generateImageFrame(prompt: string, style: string, previousFrameBase64?: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const textPart = { text: `Art Style: ${style}. Frame Description: ${prompt}` };

  const contents = previousFrameBase64 
    ? { parts: [{ inlineData: { mimeType: 'image/jpeg', data: previousFrameBase64 } }, textPart] }
    : { parts: [textPart] };

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: contents,
  });

  // Find the image part in the response
  const imagePart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (imagePart?.inlineData?.data) {
    return imagePart.inlineData.data;
  }

  throw new Error("The AI failed to generate an image frame.");
}

/**
 * Generates a comprehensive design blueprint for a political poster.
 */
export async function generatePosterBlueprint(
  mainCandidate: PersonInfo,
  secondaryPeople: PersonInfo[],
  partyName: string,
  logoCount: number,
  language: string,
  theme: string
): Promise<PosterBlueprint> {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const systemInstruction = `Role: You are an expert Political Campaign Strategist and Senior Graphic Designer specializing in Indian election aesthetics (specifically for Maharashtra and National levels).

Task: Your goal is to generate a comprehensive "Design Blueprint" for a political poster. This blueprint will be used by a web-based canvas (Fabric.js) to render a layered, editable poster.

Output Format: ALWAYS output in valid JSON format.

Design Logic Requirements:
1. Hierarchy: 
   - Main Candidate (candidate_1) should be large and central.
   - Secondary People (candidate_2, candidate_3, etc.) should be smaller, arranged at the top or bottom as supporters or party leaders.
2. Layering: 
   - Define objects in a "layers" array.
   - Every text layer should have a clear id. 
   - For every candidate photo (image), generate a corresponding text layer (type: text) with the person's name, positioned exactly below the image.
   - Use IDs like "candidate_name_1" for candidate_1, "candidate_name_2" for candidate_2.
3. Language: Use ${language} for all text content including slogans and designations.
4. Canvas: 1080x1350.
5. Slogans: Create 3 high-impact slogans in ${language} and include them as text layers.

JSON Structure Example:
{
  "posterTitle": "Title",
  "background": { "color": "gradient code" },
  "layers": [
    { "id": "candidate_1", "type": "image", "x": 540, "y": 700, "zIndex": 2 },
    { "id": "candidate_name_1", "type": "text", "content": "Name", "x": 540, "y": 900, "zIndex": 5 }
  ]
}`;

  const peopleList = [mainCandidate, ...secondaryPeople].map((p, i) => 
    `Person ${i+1}: Name: ${p.name}, Designation: ${p.designation}`
  ).join('\n');

  const prompt = `Generate a design blueprint in ${language} for:
  ${peopleList}
  Party Name/Logo: ${partyName}
  Logos to include: ${logoCount}
  Campaign Theme: ${theme}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction: systemInstruction,
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text || "{}");
}

import React, { useState } from 'react';
import { generatePosterBlueprint, PosterBlueprint, PersonInfo } from '../services/geminiService';
import { fileToBase64 } from '../utils/file';
import SpinnerIcon from './icons/SpinnerIcon';
import DownloadIcon from './icons/DownloadIcon';
import FileUpload from './FileUpload';
import TrashIcon from './icons/TrashIcon';

const LANGUAGES = ['Marathi', 'Hindi', 'English'];

interface CandidateState extends PersonInfo {
    base64: string;
}

const PosterMaker: React.FC<{ onUsage: () => void }> = ({ onUsage }) => {
    const [step, setStep] = useState<'INPUT' | 'GENERATING' | 'RESULT'>('INPUT');

    // Form State
    const [mainCandidateName, setMainCandidateName] = useState('');
    const [mainDesignation, setMainDesignation] = useState('');
    const [partyName, setPartyName] = useState('');
    const [theme, setTheme] = useState('');
    const [language, setLanguage] = useState('Marathi');

    // Candidates state (including main if we want, but let's separate main and secondary for clarity)
    const [secondaryCandidates, setSecondaryCandidates] = useState<CandidateState[]>([]);
    const [mainPhoto, setMainPhoto] = useState<string | null>(null);
    const [logos, setLogos] = useState<string[]>([]);

    const [blueprint, setBlueprint] = useState<PosterBlueprint | null>(null);
    const [error, setError] = useState<string | null>(null);

    const handleMainPhoto = async (files: FileList) => {
        const base64 = await fileToBase64(files[0]);
        setMainPhoto(base64);
    };

    const handleSecondaryPhotos = async (files: FileList) => {
        const base64s = await Promise.all(Array.from(files).map(fileToBase64));
        const newOnes = base64s.map(b => ({ base64: b, name: '', designation: '' }));
        setSecondaryCandidates(prev => [...prev, ...newOnes]);
    };

    const handleLogos = async (files: FileList) => {
        const base64s = await Promise.all(Array.from(files).map(fileToBase64));
        setLogos(prev => [...prev, ...base64s]);
    };

    const removeSecondary = (idx: number) => setSecondaryCandidates(prev => prev.filter((_, i) => i !== idx));
    const removeLogo = (idx: number) => setLogos(prev => prev.filter((_, i) => i !== idx));

    const updateSecondaryName = (idx: number, name: string) => {
        setSecondaryCandidates(prev => prev.map((c, i) => i === idx ? { ...c, name } : c));
    };

    const handleGenerate = async () => {
        if (!mainCandidateName || !partyName || !theme) {
            setError("Please fill in main candidate name, party, and theme.");
            return;
        }
        setStep('GENERATING');
        setError(null);
        try {
            const result = await generatePosterBlueprint(
                { name: mainCandidateName, designation: mainDesignation },
                secondaryCandidates.map(c => ({ name: c.name, designation: c.designation })),
                partyName,
                logos.length,
                language,
                theme
            );
            setBlueprint(result);
            setStep('RESULT');
            onUsage();
        } catch (err: any) {
            setError(err.message || "Failed to generate blueprint.");
            setStep('INPUT');
        }
    };

    const reset = () => {
        setStep('INPUT');
        setBlueprint(null);
        setMainPhoto(null);
        setSecondaryCandidates([]);
        setLogos([]);
        setMainCandidateName('');
        setMainDesignation('');
        setPartyName('');
        setTheme('');
    };

    const renderPreview = () => {
        if (!blueprint) return null;

        const W = 1080;
        const H = 1350;

        return (
            <div 
                className="relative mx-auto overflow-hidden shadow-2xl rounded-sm bg-white" 
                style={{ 
                    width: '100%', 
                    paddingBottom: `${(H / W) * 100}%`,
                    background: blueprint.background.color 
                }}
            >
                <div className="absolute inset-0">
                    {blueprint.layers.sort((a, b) => a.zIndex - b.zIndex).map((layer) => {
                        const left = (layer.x / W) * 100;
                        const top = (layer.y / H) * 100;

                        if (layer.type === 'text') {
                            return (
                                <div 
                                    key={layer.id}
                                    className="absolute transform -translate-x-1/2 -translate-y-1/2 text-center whitespace-nowrap"
                                    style={{
                                        left: `${left}%`,
                                        top: `${top}%`,
                                        fontFamily: layer.font || 'sans-serif',
                                        fontSize: `clamp(8px, ${layer.size ? layer.size / 3.5 : 18}px, 60px)`,
                                        color: layer.color || '#000',
                                        opacity: layer.opacity || 1,
                                        zIndex: layer.zIndex,
                                        fontWeight: 'bold'
                                    }}
                                >
                                    {layer.content}
                                </div>
                            );
                        } else if (layer.type === 'image') {
                            let imgSrc = null;

                            if (layer.id === 'candidate_1') {
                                if (mainPhoto) imgSrc = `data:image/jpeg;base64,${mainPhoto}`;
                            } else if (layer.id.includes('candidate')) {
                                const idx = parseInt(layer.id.split('_')[1]) - 2; // candidate_2 is index 0 of secondary
                                if (secondaryCandidates[idx]) imgSrc = `data:image/jpeg;base64,${secondaryCandidates[idx].base64}`;
                            } else if (layer.id.includes('logo')) {
                                const idx = parseInt(layer.id.split('_')[1]) - 1 || 0;
                                if (logos[idx]) imgSrc = `data:image/jpeg;base64,${logos[idx]}`;
                            }

                            return (
                                <div 
                                    key={layer.id}
                                    className="absolute transform -translate-x-1/2 -translate-y-1/2 flex items-center justify-center border border-dashed border-gray-400 bg-gray-100/30"
                                    style={{
                                        left: `${left}%`,
                                        top: `${top}%`,
                                        width: `${(layer.width || (layer.id.includes('logo') ? 150 : 400)) / W * 100}%`,
                                        height: `${(layer.height || (layer.id.includes('logo') ? 150 : 400)) / H * 100}%`,
                                        zIndex: layer.zIndex
                                    }}
                                >
                                    {imgSrc ? (
                                        <img src={imgSrc} className="w-full h-full object-contain" alt={layer.id} />
                                    ) : (
                                        <div className="flex flex-col items-center">
                                            <span className="text-[10px] text-gray-400 font-mono text-center leading-none">
                                                {layer.id.includes('logo') ? 'LOGO' : 'CANDIDATE'}<br/>{layer.id.split('_')[1] || '1'}
                                            </span>
                                        </div>
                                    )}
                                </div>
                            );
                        }
                        return null;
                    })}
                </div>
            </div>
        );
    };

    return (
        <div className="w-full max-w-6xl mx-auto space-y-6 animate-slide-fade-in pb-10">
            {step === 'INPUT' && (
                <div className="bg-surface p-8 rounded-2xl border border-border shadow-xl space-y-8">
                    <div className="flex items-center gap-3">
                        <div className="p-3 bg-secondary/10 rounded-xl">
