                                    >
                                        {lang}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="bg-surface p-5 rounded-2xl border border-border shadow-xl">
                            <label className="text-[10px] uppercase font-black text-textMuted mb-4 block tracking-widest">Voice Persona (Touch to Preview)</label>
                            <div className="flex flex-col gap-3">
                                {MALE_VOICES.map(v => (
                                    <div 
                                        key={v.id} 
                                        onClick={() => handleVoiceSelect(v)} 
                                        className={`p-4 rounded-xl border-2 cursor-pointer transition-all relative group ${selectedVoice === v.id ? 'bg-primary/10 border-primary shadow-lg shadow-primary/10' : 'bg-black/20 border-transparent hover:border-textSub'}`}
                                    >
