                                            <div className="absolute top-2 right-2 flex items-center gap-1 bg-primary text-[8px] text-white px-2 py-1 rounded-full animate-pulse font-black uppercase">
                                                <div className="w-1 h-1 bg-white rounded-full animate-bounce"></div>
