const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(() => {
      try {
          const savedSession = localStorage.getItem('active_user');
          return savedSession ? JSON.parse(savedSession) : null;
      } catch (e) {
          return null;
      }
  });

  const [users, setUsers] = useState<UserAccount[]>(() => {
      try {
          const savedUsers = localStorage.getItem('app_users');
          return savedUsers ? JSON.parse(savedUsers) : INITIAL_USERS;
      } catch (e) {
          return INITIAL_USERS;
      }
  });

  // Sync INITIAL_USERS with state (in case of new hardcoded users being added later)
  useEffect(() => {
    setUsers(prevUsers => {
        const existingEmails = new Set(prevUsers.map(u => u.email.toLowerCase()));
        const missingUsers = INITIAL_USERS.filter(u => !existingEmails.has(u.email.toLowerCase()));
        if (missingUsers.length > 0) {
            return [...prevUsers, ...missingUsers];
        }
        return prevUsers;
    });
  }, []);

  // Ensure permission migration for legacy users
  useEffect(() => {
    let updated = false;
    const migratedUsers = users.map(u => {
      if (u.permissions && typeof u.permissions.poster === 'undefined') {
        updated = true;
        return { ...u, permissions: { ...u.permissions, poster: true } };
      }
      return u;
    });

    if (updated) {
      setUsers(migratedUsers);
      if (user) {
        const currentUser = migratedUsers.find(u => u.email === user.email);
        if (currentUser) {
          setUser({
            email: currentUser.email,
            name: currentUser.name,
            role: currentUser.role,
            permissions: currentUser.permissions
          });
        }
      }
    }
  }, [users, user]);

  useEffect(() => {
    if (user) localStorage.setItem('active_user', JSON.stringify(user));
    else localStorage.removeItem('active_user');
  }, [user]);

