  const { isEnabled: isRecordingEnabled, setIsEnabled: setIsRecordingEnabled, isActive: isRecordingActive, isFinalizing: isFinalizingRecording, finalRecording, error: recordingError, startRecording, stopRecording, resetRecording } = useScreenRecorder(appContainerRef);

  const currentQuestion = currentQuestionIndex >= 0 ? questionQueue[currentQuestionIndex] : null;

