    setUsers(prev => prev.map(u => u.email === email ? { ...u, permissions } : u));
    if (user?.email === email) {
        setUser(prev => prev ? { ...prev, permissions } : null);
    }
  };

  const handleRegister = (newUser: UserAccount) => {
      setUsers(prev => [...prev, newUser]);
