interface SubscriptionModalProps {
  isOpen: boolean;
  onClose: () => void;
  onRegister: (user: UserAccount) => void;
  existingEmails: string[];
}

type PlanType = 'STUDENT' | 'CREATOR' | 'PRO';

const PLANS: Record<PlanType, { 
  name: string; 
  price: string; 
  features: string[]; 
  permissions: UserPermissions; 
  color: string;
}> = {
  STUDENT: {
    name: 'Student',
    price: 'Free',
    features: ['TTS Reader', 'Basic Voice Access'],
    permissions: { mcq: false, reader: true, video: false, proVideo: false, poster: false },
    color: 'bg-slate-500'
  },
