  MATRIX: { id: 'MATRIX', name: 'The Construct', category: 'Basic', colors: { '--color-background': '#020602', '--color-surface': 'rgba(10, 30, 10, 0.7)', '--color-primary': '#22c55e', '--color-primary-hover': '#16a34a', '--color-secondary': '#064e3b', '--color-accent': '#4ade80', '--color-border': 'rgba(34, 197, 94, 0.4)', '--color-text-main': '#f0fdf4', '--color-text-sub': '#86efac', '--color-text-muted': 'rgba(134, 239, 172, 0.5)' } },
  LABORATORY: { id: 'LABORATORY', name: 'Scientific Lab', category: 'Chemistry', colors: { '--color-background': '#0f172a', '--color-surface': 'rgba(15, 23, 42, 0.75)', '--color-primary': '#a855f7', '--color-primary-hover': '#9333ea', '--color-secondary': '#22c55e', '--color-accent': '#3b82f6', '--color-border': 'rgba(168, 85, 247, 0.3)', '--color-text-main': '#f8fafc', '--color-text-sub': '#e2e8f0', '--color-text-muted': 'rgba(203, 213, 225, 0.5)' } },
};

const SUPER_ADMIN_EMAIL = 'aroonthorat@dev.com';

const App: React.FC = () => {
  // Use userService for initial state
  const [user, setUser] = useState<User | null>(userService.getSession());
  const [users, setUsers] = useState<UserAccount[]>(userService.getAllUsers());
  const [showLogin, setShowLogin] = useState(false);

  // Changed default theme from LABORATORY to WATERCOLOR
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(THEMES.WATERCOLOR);
  const [currentLogo, setCurrentLogo] = useState<LogoVariant>('DEFAULT');
  const [showSettings, setShowSettings] = useState(false);
  const [mcqReaderTitle, setMcqReaderTitle] = useState<string>('MCQ Reader');
  const [settingsLoaded, setSettingsLoaded] = useState(false);
  const [currentView, setCurrentView] = useState<'HOME' | 'MCQ_READER' | 'READER' | 'ADMIN_DASHBOARD' | 'VIDEO_MAKER' | 'POSTER_MAKER' | 'PRO_VIDEO_MAKER' | 'BULK_EDITOR'>('HOME');
  const [questionQueue, setQuestionQueue] = useState<QuestionData[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState<number>(-1);
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [highlightedOption, setHighlightedOption] = useState<string | null>(null);
  const [generalError, setGeneralError] = useState<string | null>(null);
  const [countdown, setCountdown] = useState<number | null>(null);

  const appContainerRef = useRef<HTMLDivElement>(null);

  // Refresh user data when needed
  const refreshUserData = () => {
    setUsers(userService.getAllUsers());
    const session = userService.getSession();
    setUser(session);
  };

  useEffect(() => {
    if (user) {
        const savedSettings = localStorage.getItem(`settings_${user.email}`);
        if (savedSettings) {
            try {
                const parsed = JSON.parse(savedSettings);
                if (parsed.themeId && THEMES[parsed.themeId]) setCurrentTheme(THEMES[parsed.themeId]);
                if (parsed.logo) setCurrentLogo(parsed.logo as LogoVariant);
                if (parsed.mcqTitle) setMcqReaderTitle(parsed.mcqTitle);
            } catch (e) {}
        } else {
            setCurrentTheme(THEMES.WATERCOLOR);
            setCurrentLogo('DEFAULT');
            setMcqReaderTitle('MCQ Reader');
        }
        setSettingsLoaded(true);
    } else {
        setSettingsLoaded(false);
    }
  }, [user]);

  useEffect(() => {
    if (user && settingsLoaded) {
        const settings = { themeId: currentTheme.id, logo: currentLogo, mcqTitle: mcqReaderTitle };
        localStorage.setItem(`settings_${user.email}`, JSON.stringify(settings));
    }
  }, [currentTheme, currentLogo, mcqReaderTitle, user, settingsLoaded]);

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--color-background', currentTheme.colors['--color-background']);
    root.style.setProperty('--color-surface', currentTheme.colors['--color-surface']);
    root.style.setProperty('--color-primary', currentTheme.colors['--color-primary']);
    root.style.setProperty('--color-primary-hover', currentTheme.colors['--color-primary-hover']);
    root.style.setProperty('--color-secondary', currentTheme.colors['--color-secondary']);
    root.style.setProperty('--color-accent', currentTheme.colors['--color-accent']);
    root.style.setProperty('--color-border', currentTheme.colors['--color-border']);
    root.style.setProperty('--color-text-main', currentTheme.colors['--color-text-main']);
    root.style.setProperty('--color-text-sub', currentTheme.colors['--color-text-sub']);
    root.style.setProperty('--color-text-muted', currentTheme.colors['--color-text-muted']);
  }, [currentTheme]);

  const { isEnabled: isRecordingEnabled, setIsEnabled: setIsRecordingEnabled, isActive: isRecordingActive, isFinalizing: isFinalizingRecording, finalRecording, error: recordingError, startRecording, stopRecording, resetRecording } = useScreenRecorder(appContainerRef);

  const currentQuestion = currentQuestionIndex >= 0 ? questionQueue[currentQuestionIndex] : null;

  const handleUpdatePermissions = (email: string, permissions: UserPermissions) => {
      userService.updatePermissions(email, permissions);
      refreshUserData();
  };

  const handleRegister = async (newUser: UserAccount) => {
      try {
          const loggedInUser = await userService.register(newUser);
          setUser(loggedInUser);
          refreshUserData();
      } catch (e) {
          console.error(e);
      }
  };

  const trackUsage = useCallback((type: 'MCQ' | 'TTS' | 'ANIMATION' | 'POSTER', count: number = 1) => {
    if (!user) return;
    userService.trackUsage(user.email);
  }, [user]);

  const resetToHome = useCallback(() => {
    resetRecording();
    setQuestionQueue([]);
    setCurrentQuestionIndex(-1);
    setAppState(AppState.IDLE);
    setHighlightedOption(null);
    setGeneralError(null);
    setCountdown(null);
    setCurrentView('HOME');
  }, [resetRecording]);

  const goToNextQuestion = useCallback(() => {
    if (currentQuestionIndex < questionQueue.length - 1) {
      setTimeout(() => {
        setCurrentQuestionIndex(prev => prev + 1);
        setHighlightedOption(null);
        setCountdown(null);
        setAppState(AppState.DISPLAYING_QUESTION);
      }, 2000);
    }
  }, [currentQuestionIndex, questionQueue.length]);

  const handleFileSelect = async (files: FileList) => {
    initAudio();
    setGeneralError(null);
    setQuestionQueue([]);
    setCurrentQuestionIndex(-1);
    setHighlightedOption(null);
    setCountdown(null);
    trackUsage('MCQ', files.length);
    await startRecording();
    setAppState(AppState.PROCESSING_IMAGE);
    try {
      const processingPromises = Array.from(files).map(async (file) => {
        const base64Image = await fileToBase64(file);
        return await processQuestionImage(base64Image);
      });
      const results = await Promise.all(processingPromises);
      setAppState(AppState.PREPARING_AUDIO);
      const audioEnhancedQuestions = await Promise.all(results.map(async (q: QuestionData) => {
        const qText = `${q.question}. ${q.options.map(o => `Option ${o.letter}. ${o.text}`).join('. ')}`;
        const correct = q.options.find(o => o.letter === q.correctOption);
        const aText = `The correct answer is option ${correct?.letter}. ${correct?.text}.`;
        const [questionAudio, answerAudio] = await Promise.all([textToSpeech(qText), textToSpeech(aText)]);
        return { ...q, questionAudio, answerAudio };
      }));
      setQuestionQueue(audioEnhancedQuestions);
      setCurrentQuestionIndex(0);
      setAppState(AppState.DISPLAYING_QUESTION);
    } catch (err: any) {
      setGeneralError(`Failed to process batch. ${err.message || String(err)}`);
      setAppState(AppState.IDLE);
      resetRecording(); 
    }
  };

  useEffect(() => {
    if (appState === AppState.DISPLAYING_QUESTION && currentQuestion) {
      const timer = setTimeout(() => setAppState(AppState.READING_ALOUD), 3000);
      return () => clearTimeout(timer);
    }
  }, [appState, currentQuestion]);

  useEffect(() => {
    const runAudioWorkflow = async () => {
      if (appState === AppState.READING_ALOUD && currentQuestion?.questionAudio) {
        try {
          await playAudio(currentQuestion.questionAudio);
          setAppState(AppState.COUNTDOWN);
        } catch (err) {
          setAppState(AppState.IDLE);
        }
      } else if (appState === AppState.REVEALING_ANSWER && currentQuestion?.answerAudio) {
        const correctOption = currentQuestion.options.find(o => o.letter === currentQuestion.correctOption);
        if (correctOption) {
          setHighlightedOption(correctOption.letter);
          try {
            await playAudio(currentQuestion.answerAudio);
            goToNextQuestion();
          } catch (err) {}
        }
      }
    };
    runAudioWorkflow();
  }, [appState, currentQuestion, goToNextQuestion]);

  useEffect(() => {
    if (appState !== AppState.COUNTDOWN) return;
    let currentCount = 5;
    setCountdown(currentCount);
    playBeep();
    const intervalId = setInterval(() => {
      currentCount -= 1;
      if (currentCount > 0) {
        setCountdown(currentCount);
        playBeep();
      } else {
        clearInterval(intervalId);
        setAppState(AppState.REVEALING_ANSWER);
      }
    }, 1000);
    return () => clearInterval(intervalId);
  }, [appState]);

  const isLastQuestion = questionQueue.length > 0 && currentQuestionIndex === questionQueue.length - 1;
  const showTryAgain = isLastQuestion && appState === AppState.REVEALING_ANSWER;

  useEffect(() => {
    if (showTryAgain && isRecordingActive) stopRecording();
  }, [showTryAgain, isRecordingActive, stopRecording]);

  const handleDownloadRecording = () => {
    if (!finalRecording) return;
    const blob = finalRecording as Blob;
    const url = window.URL.createObjectURL(blob);
    const firstWord = questionQueue[0]?.question.split(' ')[0].replace(/[^a-zA-Z0-9]/g, '') || 'session';
    const a = document.createElement('a');
    a.href = url;
    a.download = `${firstWord}-reader-session.${blob.type.split('/')[1] || 'webm'}`;
    document.body.appendChild(a);
    a.click();
    window.URL.revokeObjectURL(url);
    a.remove();
  };

  const getStatusMessage = () => {
    if (isFinalizingRecording) return "Finalizing screen recording...";
    if (appState === AppState.PROCESSING_IMAGE || appState === AppState.PREPARING_AUDIO) return "Loading...";
    if (appState === AppState.REVEALING_ANSWER && isLastQuestion) return "All questions complete!";
    return null;
  };

  const getHeaderContent = () => {
    switch(currentView) {
        case 'MCQ_READER': return { title: mcqReaderTitle, subtitle: '', logoSize: 'w-24 h-24', titleSize: 'text-3xl', subtitleSize: 'text-base', headerMargin: 'mb-4' };
        case 'READER': return { title: 'Text to Speech Reader', subtitle: 'Type text to generate audio', logoSize: 'w-24 h-24', titleSize: 'text-3xl', subtitleSize: 'text-base', headerMargin: 'mb-4' };
        case 'VIDEO_MAKER': return { title: 'Animation Studio', subtitle: 'AI Generated Frame Sequences', logoSize: 'w-24 h-24', titleSize: 'text-3xl', subtitleSize: 'text-base', headerMargin: 'mb-4' };
        case 'PRO_VIDEO_MAKER': return { title: 'Cinematic Director', subtitle: 'Powered by Veo 3.1', logoSize: 'w-24 h-24', titleSize: 'text-3xl', subtitleSize: 'text-base', headerMargin: 'mb-4' };
        case 'BULK_EDITOR': return { title: 'Photo Lab', subtitle: 'Batch AI Restoration', logoSize: 'w-24 h-24', titleSize: 'text-3xl', subtitleSize: 'text-base', headerMargin: 'mb-4' };
        case 'POSTER_MAKER': return { title: 'Campaign Planner', subtitle: 'AI Political Strategy & Design', logoSize: 'w-24 h-24', titleSize: 'text-3xl', subtitleSize: 'text-base', headerMargin: 'mb-4' };
        case 'ADMIN_DASHBOARD': return { title: 'Admin Dashboard', subtitle: 'System Status & User Management', logoSize: 'w-24 h-24', titleSize: 'text-3xl', subtitleSize: 'text-base', headerMargin: 'mb-4' };
        default: return { title: 'Synapse', subtitle: 'An AI Toolroom', logoSize: 'w-40 h-40', titleSize: 'text-4xl', subtitleSize: 'text-lg', headerMargin: 'mb-8' };
    }
  };

  const isSuperAdmin = user?.email.toLowerCase() === SUPER_ADMIN_EMAIL.toLowerCase();

  if (!user) return (
    <div className="min-h-screen text-textMain flex flex-col items-center justify-center p-4 font-sans relative overflow-hidden z-10">
      <BackgroundController theme={currentTheme} />
      {showLogin ? (
        <LoginPage 
          onLogin={setUser} 
          onRegister={handleRegister} 
          onBack={() => setShowLogin(false)}
          users={users} 
          logoVariant={currentLogo} 
        />
      ) : (
        <LandingPage onLoginClick={() => setShowLogin(true)} />
      )}
    </div>
  );

  const headerContent = getHeaderContent();
  const displayError = (generalError || recordingError) as string | null;

  return (
    <div ref={appContainerRef} className="min-h-screen text-textMain flex flex-col items-center justify-center p-4 font-sans relative transition-colors duration-500 overflow-hidden z-0">
      <BackgroundController theme={currentTheme} />
      {currentView !== 'HOME' && <button onClick={resetToHome} className="absolute top-4 left-4 text-textSub hover:text-textMain transition-colors p-2 rounded-full hover:bg-surface z-20"><ArrowLeftIcon className="w-8 h-8" /></button>}
      <div className="absolute top-4 right-4 flex items-center gap-3 z-20">
         {isSuperAdmin && <div className="px-3 py-1 bg-surface border border-primary rounded-full text-xs text-primary font-bold uppercase tracking-wider">Admin Mode</div>}
         <button onClick={() => setShowSettings(true)} className="p-2 text-textSub hover:text-textMain hover:bg-surface rounded-full border border-transparent hover:border-border"><SettingsIcon className="w-6 h-6" /></button>
      </div>
      <SettingsModal isOpen={showSettings} onClose={() => setShowSettings(false)} themes={Object.values(THEMES)} currentTheme={currentTheme} onSetTheme={setCurrentTheme} currentLogo={currentLogo} onSetLogo={setCurrentLogo} mcqReaderTitle={mcqReaderTitle} onSetMcqReaderTitle={setMcqReaderTitle} />
      <div className="w-full max-w-4xl mx-auto animate-slide-fade-in flex flex-col items-center relative z-10">
        <header className={`text-center flex flex-col items-center transition-all ${headerContent.headerMargin}`}>
            <LogoIcon variant={currentLogo} className={`transition-all ${headerContent.logoSize}`} />
            <h1 className={`font-extrabold text-textMain tracking-tight mt-4 animate-text-glow transition-all ${headerContent.titleSize}`}>{headerContent.title}</h1>
            <p className={`text-textSub mt-2 transition-opacity ${headerContent.subtitleSize}`}>{headerContent.subtitle}</p>
        </header>
        <main className="w-full max-w-2xl mx-auto">
            {currentView === 'HOME' && (
              <HomeScreen 
                user={user} 
                onSelectMCQReader={() => setCurrentView('MCQ_READER')} 
                onSelectReader={() => setCurrentView('READER')} 
                onSelectVideoMaker={() => setCurrentView('VIDEO_MAKER')}
                onSelectProVideoMaker={() => setCurrentView('PRO_VIDEO_MAKER')}
                onSelectPosterMaker={() => setCurrentView('POSTER_MAKER')}
                onSelectBulkEditor={() => setCurrentView('BULK_EDITOR')}
                onSelectAdmin={() => setCurrentView('ADMIN_DASHBOARD')} 
                onOpenSettings={() => setShowSettings(true)} 
                mcqReaderTitle={mcqReaderTitle} 
              />
            )}
            {/* Strict security check for admin dashboard rendering */}
            {currentView === 'ADMIN_DASHBOARD' && isSuperAdmin && <AdminDashboard users={users} onAddUser={(u) => { userService.addUser(u); refreshUserData(); }} onDeleteUser={(e) => { userService.deleteUser(e); refreshUserData(); }} onUpdatePermissions={handleUpdatePermissions} currentUserEmail={user.email} themes={Object.values(THEMES)} currentTheme={currentTheme} onSetTheme={setCurrentTheme} />}
            {currentView === 'MCQ_READER' && (
            <>
              {displayError && <div className="bg-red-900/50 border border-red-500 text-red-300 p-4 mb-6 rounded-md text-center"><p className="font-bold">Error</p><p>{displayError}</p></div>}
              <div className="h-8 mb-4 text-center text-textSub flex items-center justify-center space-x-2">{(getStatusMessage()) && <SpinnerIcon />}<span>{getStatusMessage()}</span>{questionQueue.length > 0 && !showTryAgain && <span className="font-semibold">({currentQuestionIndex + 1}/{questionQueue.length})</span>}</div>
              {!currentQuestion && !showTryAgain ? (
                <>
                  <div className="flex items-center justify-center mb-4 space-x-2 p-2 rounded-md bg-surface"><input type="checkbox" id="record-session" checked={isRecordingEnabled} onChange={(e) => setIsRecordingEnabled(e.target.checked)} className="w-4 h-4 text-primary bg-gray-700 border-border rounded" /><label htmlFor="record-session" className="text-sm font-medium text-textSub cursor-pointer">Record Session</label></div>
                  <FileUpload onFileSelect={handleFileSelect} disabled={appState === AppState.PROCESSING_IMAGE} />
                </>
              ) : (currentQuestion && <div className="relative bg-surface rounded-2xl p-6 border border-border animate-pulse-glow"><QuestionDisplay questionData={currentQuestion} highlightedOption={highlightedOption} />{appState === AppState.COUNTDOWN && countdown !== null && <div className="absolute inset-0 bg-black/40 flex items-center justify-center rounded-lg z-10"><span key={countdown} className="text-9xl font-bold text-white animate-pop-in">{countdown}</span></div>}</div>)}
              {showTryAgain && <div className="mt-8 text-center flex flex-col sm:flex-row gap-4 justify-center"><button onClick={resetToHome} className="px-8 py-3 bg-secondary text-white font-semibold rounded-lg hover:opacity-90">Back to Home</button>{finalRecording && <button onClick={handleDownloadRecording} className="px-8 py-3 bg-primary text-white font-semibold rounded-lg hover:bg-primary-hover">Download Recording</button>}</div>}
            </>
            )}
            {currentView === 'READER' && <Suspense fallback={<div className="flex justify-center p-10 text-primary"><SpinnerIcon /></div>}><Reader onUsage={() => trackUsage('TTS')} /></Suspense>}
            {currentView === 'VIDEO_MAKER' && <Suspense fallback={<div className="flex justify-center p-10 text-primary"><SpinnerIcon /></div>}><AnimationTool onUsage={() => trackUsage('ANIMATION')} /></Suspense>}
            {currentView === 'POSTER_MAKER' && <Suspense fallback={<div className="flex justify-center p-10 text-primary"><SpinnerIcon /></div>}><PosterMaker onUsage={() => trackUsage('POSTER')} /></Suspense>}
            {currentView === 'PRO_VIDEO_MAKER' && <Suspense fallback={<div className="flex justify-center p-10 text-primary"><SpinnerIcon /></div>}><ProVideoMaker onUsage={() => trackUsage('ANIMATION')} /></Suspense>}
            {currentView === 'BULK_EDITOR' && <Suspense fallback={<div className="flex justify-center p-10 text-primary"><SpinnerIcon /></div>}><BulkImageEditor onUsage={() => trackUsage('ANIMATION')} /></Suspense>}
        </main>
        <footer className="text-center mt-8 text-sm text-textSub"><p>Powered by Google Gemini</p><button onClick={() => { userService.logout(); setUser(null); }} className="text-xs mt-2 text-primary hover:text-textMain underline">Logout ({user.name})</button></footer>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { UserAccount, UserPermissions } from '../types';
import CloseIcon from './icons/CloseIcon';
import CheckIcon from './icons/CheckIcon';
import SpinnerIcon from './icons/SpinnerIcon';
import CreditCardIcon from './icons/CreditCardIcon';

interface SubscriptionModalProps {
  isOpen: boolean;
  onClose: () => void;
  onRegister: (user: UserAccount) => void;
  existingEmails: string[];
}

type PlanType = 'STUDENT' | 'CREATOR' | 'PRO';

const PLANS: Record<PlanType, { 
  name: string; 
  price: string; 
  features: string[]; 
  permissions: UserPermissions; 
  color: string;
}> = {
  STUDENT: {
    name: 'Student',
    price: 'Free',
    features: ['TTS Reader', 'Basic Voice Access'],
    permissions: { mcq: false, reader: true, video: false, proVideo: false, poster: false, bulkEditor: false },
    color: 'bg-slate-500'
  },
  CREATOR: {
    name: 'Creator',
    price: '$12/mo',
    features: ['Animation Studio', 'TTS Reader', 'Voice Cloning', 'Bulk Photo Editor'],
    permissions: { mcq: false, reader: true, video: true, proVideo: false, poster: false, bulkEditor: true },
    color: 'bg-secondary'
  },
  PRO: {
    name: 'Professional',
    price: '$39/mo',
    features: ['Cinematic Video (Veo)', 'Poster Architect', 'Full Suite Access', 'Priority Processing'],
    permissions: { mcq: true, reader: true, video: true, proVideo: true, poster: true, bulkEditor: true },
    color: 'bg-gradient-to-r from-primary to-accent'
  }
};

const SubscriptionModal: React.FC<SubscriptionModalProps> = ({ isOpen, onClose, onRegister, existingEmails }) => {
  const [step, setStep] = useState<1 | 2 | 3>(1);
  const [selectedPlan, setSelectedPlan] = useState<PlanType | null>(null);

  // Registration State
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  // Payment State
  const [cardNumber, setCardNumber] = useState('');
  const [expiry, setExpiry] = useState('');
  const [cvc, setCvc] = useState('');

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  if (!isOpen) return null;

  const handleNextStep = () => {
    setError(null);
    if (step === 1 && selectedPlan) {
      setStep(2);
    } else if (step === 2) {
      if (!name || !email || !password) {
        setError("Please fill in all account details.");
        return;
      }
      if (existingEmails.includes(email.toLowerCase())) {
        setError("Email already exists. Please login.");
        return;
      }
      // Skip payment for free plan
      if (PLANS[selectedPlan!].price === 'Free') {
        handleSubmit();
      } else {
        setStep(3);
      }
    }
  };

  const handleSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!selectedPlan) return;

    // Basic mock validation
    if (PLANS[selectedPlan].price !== 'Free') {
        if (cardNumber.length < 12 || expiry.length < 4 || cvc.length < 3) {
            setError("Please enter valid card details (Mock: Any 16 digits).");
            return;
        }
    }

    setIsLoading(true);

    // Simulate API processing
    setTimeout(() => {
        onRegister({
            name,
            email,
            password,
            role: 'USER',
            permissions: PLANS[selectedPlan].permissions,
            stats: { mcqGenerations: 0, ttsGenerations: 0, lastActive: 'Just Joined' }
        });
        setIsLoading(false);
        onClose();
    }, 2000);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-md transition-opacity" onClick={onClose}></div>
      <div className="relative w-full max-w-4xl bg-surface rounded-3xl border border-border shadow-2xl animate-pop-in flex flex-col overflow-hidden max-h-[90vh]">

        {/* Header */}
        <div className="p-6 border-b border-border flex justify-between items-center bg-black/20">
            <div>
                <h2 className="text-xl font-bold text-textMain">
                    {step === 1 && "Choose Your Plan"}
                    {step === 2 && "Create Your Account"}
                    {step === 3 && "Secure Payment"}
                </h2>
                <div className="flex gap-2 mt-2">
                    <div className={`h-1 w-8 rounded-full ${step >= 1 ? 'bg-primary' : 'bg-gray-700'}`}></div>
                    <div className={`h-1 w-8 rounded-full ${step >= 2 ? 'bg-primary' : 'bg-gray-700'}`}></div>
                    <div className={`h-1 w-8 rounded-full ${step >= 3 ? 'bg-primary' : 'bg-gray-700'}`}></div>
                </div>
            </div>
            <button onClick={onClose} className="p-2 text-textSub hover:text-white"><CloseIcon className="w-6 h-6" /></button>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-6">

            {/* Step 1: Plans */}
            {step === 1 && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    {(Object.keys(PLANS) as PlanType[]).map((type) => {
                        const plan = PLANS[type];
                        const isSelected = selectedPlan === type;
                        return (
                            <div 
                                key={type}
                                onClick={() => setSelectedPlan(type)}
                                className={`relative p-6 rounded-2xl border-2 cursor-pointer transition-all duration-300 flex flex-col ${isSelected ? 'border-primary bg-primary/10 scale-105 shadow-xl' : 'border-border bg-black/20 hover:border-textSub'}`}
                            >
                                <div className={`absolute top-0 left-0 right-0 h-2 rounded-t-xl ${plan.color}`}></div>
                                <h3 className="text-lg font-bold text-textMain mt-2">{plan.name}</h3>
                                <div className="text-2xl font-black text-textMain my-2">{plan.price}</div>
                                <ul className="flex-1 space-y-3 mt-4 mb-6">
                                    {plan.features.map(f => (
                                        <li key={f} className="flex items-center gap-2 text-sm text-textSub">
                                            <div className="text-primary"><CheckIcon /></div> {f}
                                        </li>
                                    ))}
                                </ul>
                                <button className={`w-full py-2 rounded-lg font-bold text-sm ${isSelected ? 'bg-primary text-white' : 'bg-surface text-textSub'}`}>
                                    {isSelected ? 'Selected' : 'Choose Plan'}
                                </button>
                            </div>
                        );
                    })}
                </div>
            )}

            {/* Step 2: Account Info */}
            {step === 2 && (
                <div className="max-w-md mx-auto space-y-6 animate-slide-fade-in">
                    <div className="space-y-4">
                        <div>
                            <label className="text-xs font-bold text-textSub uppercase mb-1 block">Full Name</label>
                            <input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-1 focus:ring-primary outline-none" placeholder="John Doe" />
                        </div>
                        <div>
                            <label className="text-xs font-bold text-textSub uppercase mb-1 block">Email Address</label>
                            <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="w-full px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-1 focus:ring-primary outline-none" placeholder="john@example.com" />
                        </div>
                        <div>
                            <label className="text-xs font-bold text-textSub uppercase mb-1 block">Password</label>
                            <input type="password" value={password} onChange={e => setPassword(e.target.value)} className="w-full px-4 py-3 bg-black/20 border border-border rounded-xl text-textMain focus:ring-1 focus:ring-primary outline-none" placeholder="••••••••" />
                        </div>
                    </div>
                </div>
            )}

            {/* Step 3: Payment */}
            {step === 3 && (
                <div className="max-w-md mx-auto space-y-6 animate-slide-fade-in">
                    <div className="bg-gradient-to-br from-gray-900 to-black p-6 rounded-2xl border border-border shadow-2xl relative overflow-hidden">
                        <div className="absolute top-0 right-0 p-4 opacity-10"><CreditCardIcon className="w-32 h-32 text-white" /></div>
                        <div className="relative z-10 space-y-6">
                            <div className="flex justify-between items-center text-white/50 text-xs font-mono">
                                <span>CREDIT CARD</span>
                                <span>SECURE</span>
                            </div>
                            <div>
                                <label className="text-[10px] text-white/70 uppercase tracking-widest block mb-1">Card Number</label>
                                <input type="text" value={cardNumber} onChange={e => setCardNumber(e.target.value)} maxLength={19} className="w-full bg-transparent border-b border-white/20 text-xl font-mono text-white placeholder-white/20 outline-none focus:border-primary" placeholder="0000 0000 0000 0000" />
                            </div>
                            <div className="flex gap-4">
                                <div className="flex-1">
                                    <label className="text-[10px] text-white/70 uppercase tracking-widest block mb-1">Expiry</label>
                                    <input type="text" value={expiry} onChange={e => setExpiry(e.target.value)} maxLength={5} className="w-full bg-transparent border-b border-white/20 text-lg font-mono text-white placeholder-white/20 outline-none focus:border-primary" placeholder="MM/YY" />
                                </div>
                                <div className="w-24">
                                    <label className="text-[10px] text-white/70 uppercase tracking-widest block mb-1">CVC</label>
                                    <input type="text" value={cvc} onChange={e => setCvc(e.target.value)} maxLength={3} className="w-full bg-transparent border-b border-white/20 text-lg font-mono text-white placeholder-white/20 outline-none focus:border-primary" placeholder="123" />
                                </div>
                            </div>
                            <div className="text-right text-xs text-white/50">{name || 'YOUR NAME'}</div>
                        </div>
                    </div>

                    <div className="flex items-center gap-2 p-3 bg-blue-500/10 border border-blue-500/20 rounded-lg">
                        <div className="w-4 h-4 bg-blue-500 rounded-full flex items-center justify-center text-[10px] text-white font-bold">i</div>
                        <p className="text-xs text-blue-200">This is a mock payment. You won't be charged.</p>
                    </div>
                </div>
            )}

            {error && <p className="text-center text-red-400 text-sm bg-red-900/10 p-2 rounded-lg border border-red-500/20 mt-4">{error}</p>}

        </div>

        {/* Footer */}
        <div className="p-6 border-t border-border bg-black/20 flex justify-between items-center">
            {step > 1 ? (
                <button onClick={() => setStep(prev => prev - 1 as any)} className="text-textSub hover:text-textMain text-sm font-semibold">Back</button>
            ) : (
                <div></div>
            )}

            <button 
                onClick={step === 3 || (step === 2 && selectedPlan && PLANS[selectedPlan].price === 'Free') ? handleSubmit : handleNextStep}
                disabled={!selectedPlan || isLoading}
                className={`px-8 py-3 rounded-xl font-bold flex items-center gap-2 transition-all ${!selectedPlan ? 'bg-gray-700 text-gray-400 cursor-not-allowed' : 'bg-primary text-white hover:bg-primary-hover shadow-lg'}`}
            >
                {isLoading && <SpinnerIcon />}
                {step === 3 ? `Pay ${selectedPlan ? PLANS[selectedPlan].price : ''} & Join` : (step === 2 && selectedPlan && PLANS[selectedPlan].price === 'Free' ? 'Create Free Account' : 'Continue')}
            </button>
        </div>

      </div>
    </div>
  );
};

