                            style={{
                                left: `${el.x}%`,
                                top: `${el.y}%`,
                                width: `${el.width}%`,
                                height: `${el.height}%`,
                                fontSize: 'clamp(10px, 1.5vw, 24px)', // Responsive font sizing approximation
                            }}
                          >
                              {el.type === 'math' ? (
                                  <div className="w-full h-full font-mono text-secondary font-bold text-[0.8em] bg-black/5 p-1 overflow-hidden break-words leading-tight">
                                      <span className="text-[8px] absolute top-0 right-0 bg-secondary text-white px-1 opacity-0 group-hover:opacity-100">LaTeX</span>
                                      {el.content}
                                  </div>
                              ) : el.type === 'shape' ? (
                                  <div className="w-full h-full bg-gray-200/50"></div>
                              ) : (
                                  <div className="w-full h-full text-black p-0.5 leading-snug whitespace-pre-wrap font-serif" style={{ color: el.color || 'black' }}>
                                      {el.content}
                                  </div>
                              )}
                          </div>
                      ))}
                  </div>
              </div>

              {/* Sidebar Properties */}
              <div className="w-80 bg-surface border border-border rounded-2xl p-6 flex flex-col gap-6 shadow-xl overflow-y-auto custom-scrollbar">
                  <h3 className="text-sm font-bold text-textSub uppercase tracking-wider border-b border-border pb-2">Properties</h3>

                  {selectedElement ? (
                      <div className="space-y-6 animate-slide-fade-in">
